export const ARTICLES_01: Article[] = [
  { id: 'ccyc-art-19', lawId: 'codigo-civil-comercial', number: '19', order: 19, title: "Comienzo de la existencia", originalText: "Comienzo de la existencia. La existencia de la persona humana comienza con la concepción.", currentText: "Comienzo de la existencia. La existencia de la persona humana comienza con la concepción.", plainLanguageExplanation: "Establece el régimen de comienzo de la existencia. La existencia de la persona humana comienza con la concepción.", practicalEffects: ['En la práctica, este artículo rige comienzo de la existencia. La existencia de la persona humana comienza con la concepción.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['comienzo', 'existencia', 'articulo 19'], segments: [], amendments: [] },
  { id: 'ccyc-art-20', lawId: 'codigo-civil-comercial', number: '20', order: 20, title: "Duración del embarazo", originalText: "Duración del embarazo. Epoca de la concepción. Epoca de la concepción es el lapso entre el máximo y el mínimo fijados para la duración del embarazo. Se presume, excepto prueba en contrario, que el máximo de tiempo del embarazo es de trescientos días y el mínimo de ciento ochenta, excluyendo el día del nacimiento.", currentText: "Duración del embarazo. Epoca de la concepción. Epoca de la concepción es el lapso entre el máximo y el mínimo fijados para la duración del embarazo. Se presume, excepto prueba en contrario, que el máximo de tiempo del embarazo es de trescientos días y el mínimo de ciento ochenta, excluyendo el día del nacimiento.", plainLanguageExplanation: "Establece el régimen de duración del embarazo. Epoca de la concepción.", practicalEffects: ['En la práctica, este artículo rige duración del embarazo. Epoca de la concepción.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['duracin', 'embarazo', 'articulo 20'], segments: [], amendments: [] },
  { id: 'ccyc-art-21', lawId: 'codigo-civil-comercial', number: '21', order: 21, title: "Nacimiento con vida", originalText: "Nacimiento con vida. Los derechos y obligaciones del concebido o implantado en la mujer quedan irrevocablemente adquiridos si nace con vida. Si no nace con vida, se considera que la persona nunca existió. El nacimiento con vida se presume. CAPITULO 2 Capacidad SECCION 1ª Principios generales", currentText: "Nacimiento con vida. Los derechos y obligaciones del concebido o implantado en la mujer quedan irrevocablemente adquiridos si nace con vida. Si no nace con vida, se considera que la persona nunca existió. El nacimiento con vida se presume. CAPITULO 2 Capacidad SECCION 1ª Principios generales", plainLanguageExplanation: "Establece el régimen de nacimiento con vida. Los derechos y obligaciones del concebido o implantado en la mujer quedan irrevocablemente adquiridos si nace con vida.", practicalEffects: ['En la práctica, este artículo rige nacimiento con vida. Los derechos y obligaciones del concebido o implantado en la mujer quedan irrevocablemente adquiridos si nace con vida.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['nacimiento', 'vida', 'articulo 21'], segments: [], amendments: [] },
  { id: 'ccyc-art-22', lawId: 'codigo-civil-comercial', number: '22', order: 22, title: "Capacidad de derecho", originalText: "Capacidad de derecho. Toda persona humana goza de la aptitud para ser titular de derechos y deberes jurídicos. La ley puede privar o limitar esta capacidad respecto de hechos, simples actos, o actos jurídicos determinados.", currentText: "Capacidad de derecho. Toda persona humana goza de la aptitud para ser titular de derechos y deberes jurídicos. La ley puede privar o limitar esta capacidad respecto de hechos, simples actos, o actos jurídicos determinados.", plainLanguageExplanation: "Establece el régimen de capacidad de derecho. Toda persona humana goza de la aptitud para ser titular de derechos y deberes jurídicos.", practicalEffects: ['En la práctica, este artículo rige capacidad de derecho. Toda persona humana goza de la aptitud para ser titular de derechos y deberes jurídicos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['capacidad', 'derecho', 'articulo 22'], segments: [], amendments: [] },
  { id: 'ccyc-art-23', lawId: 'codigo-civil-comercial', number: '23', order: 23, title: "Capacidad de ejercicio", originalText: "Capacidad de ejercicio. Toda persona humana puede ejercer por sí misma sus derechos, excepto las limitaciones expresamente previstas en este Código y en una sentencia judicial.", currentText: "Capacidad de ejercicio. Toda persona humana puede ejercer por sí misma sus derechos, excepto las limitaciones expresamente previstas en este Código y en una sentencia judicial.", plainLanguageExplanation: "Establece el régimen de capacidad de ejercicio. Toda persona humana puede ejercer por sí misma sus derechos, excepto las limitaciones expresamente previstas en este Código y en una sentencia judicial.", practicalEffects: ['En la práctica, este artículo rige capacidad de ejercicio. Toda persona humana puede ejercer por sí misma sus derechos, excepto las limitaciones expresamente previstas en este Código y en una sentencia judicia'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['capacidad', 'ejercicio', 'articulo 23'], segments: [], amendments: [] },
  { id: 'ccyc-art-24', lawId: 'codigo-civil-comercial', number: '24', order: 24, title: "Personas incapaces de ejercicio", originalText: "Personas incapaces de ejercicio. Son incapaces de ejercicio: a) la persona por nacer; b) la persona que no cuenta con la edad y grado de madurez suficiente, con el alcance dispuesto en la Sección 2ª de este Capítulo; c) la persona declarada incapaz por sentencia judicial, en la extensión dispuesta en esa decisión. SECCION 2ª Persona menor de edad", currentText: "Personas incapaces de ejercicio. Son incapaces de ejercicio: a) la persona por nacer; b) la persona que no cuenta con la edad y grado de madurez suficiente, con el alcance dispuesto en la Sección 2ª de este Capítulo; c) la persona declarada incapaz por sentencia judicial, en la extensión dispuesta en esa decisión. SECCION 2ª Persona menor de edad", plainLanguageExplanation: "Establece el régimen de personas incapaces de ejercicio. Son incapaces de ejercicio: a) la persona por nacer; b) la persona que no cuenta con la edad y grado de madurez suficiente, con el alcance dispuesto en la Sección 2ª de este Capítulo; c) la persona declarada incapaz por sentencia judicial, en la extensión dispuesta en esa decisión.", practicalEffects: ['En la práctica, este artículo rige personas incapaces de ejercicio. Son incapaces de ejercicio: a) la persona por nacer; b) la persona que no cuenta con la edad y grado de madurez suficiente, con el alcance dispuesto e'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['personas', 'incapaces', 'ejercicio', 'articulo 24'], segments: [], amendments: [] },
  { id: 'ccyc-art-25', lawId: 'codigo-civil-comercial', number: '25', order: 25, title: "Menor de edad y adolescente", originalText: "Menor de edad y adolescente. Menor de edad es la persona que no ha cumplido dieciocho años. Este Código denomina adolescente a la persona menor de edad que cumplió trece años.", currentText: "Menor de edad y adolescente. Menor de edad es la persona que no ha cumplido dieciocho años. Este Código denomina adolescente a la persona menor de edad que cumplió trece años.", plainLanguageExplanation: "Establece el régimen de menor de edad y adolescente. Menor de edad es la persona que no ha cumplido dieciocho años.", practicalEffects: ['En la práctica, este artículo rige menor de edad y adolescente. Menor de edad es la persona que no ha cumplido dieciocho años.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['menor', 'edad', 'adolescente', 'articulo 25'], segments: [], amendments: [] },
  { id: 'ccyc-art-26', lawId: 'codigo-civil-comercial', number: '26', order: 26, title: "Ejercicio de los derechos por la persona menor de edad", originalText: "Ejercicio de los derechos por la persona menor de edad. La persona menor de edad ejerce sus derechos a través de sus representantes legales. No obstante, la que cuenta con edad y grado de madurez suficiente puede ejercer por sí los actos que le son permitidos por el ordenamiento jurídico. En situaciones de conflicto de intereses con sus representantes legales, puede intervenir con asistencia letrada. La persona menor de edad tiene derecho a ser oída en todo proceso judicial que le concierne así como a participar en las decisiones sobre su persona. Se presume que el adolescente entre trece y dieciséis años tiene aptitud para decidir por sí respecto de aquellos tratamientos que no resultan invasivos, ni comprometen su estado de salud o provocan un riesgo grave en su vida o integridad física. Si se trata de tratamientos invasivos que comprometen su estado de salud o está en riesgo la integridad o la vida, el adolescente debe prestar su consentimiento con la asistencia de sus progenitores; el conflicto entre ambos se resuelve teniendo en cuenta su interés superior, sobre la base de la opinión médica respecto a las consecuencias de la realización o no del acto médico. A partir de los dieciséis años el adolescente es considerado como un adulto para las decisiones atinentes al cuidado de su propio cuerpo.", currentText: "Ejercicio de los derechos por la persona menor de edad. La persona menor de edad ejerce sus derechos a través de sus representantes legales. No obstante, la que cuenta con edad y grado de madurez suficiente puede ejercer por sí los actos que le son permitidos por el ordenamiento jurídico. En situaciones de conflicto de intereses con sus representantes legales, puede intervenir con asistencia letrada. La persona menor de edad tiene derecho a ser oída en todo proceso judicial que le concierne así como a participar en las decisiones sobre su persona. Se presume que el adolescente entre trece y dieciséis años tiene aptitud para decidir por sí respecto de aquellos tratamientos que no resultan invasivos, ni comprometen su estado de salud o provocan un riesgo grave en su vida o integridad física. Si se trata de tratamientos invasivos que comprometen su estado de salud o está en riesgo la integridad o la vida, el adolescente debe prestar su consentimiento con la asistencia de sus progenitores; el conflicto entre ambos se resuelve teniendo en cuenta su interés superior, sobre la base de la opinión médica respecto a las consecuencias de la realización o no del acto médico. A partir de los dieciséis años el adolescente es considerado como un adulto para las decisiones atinentes al cuidado de su propio cuerpo.", plainLanguageExplanation: "Establece el régimen de ejercicio de los derechos por la persona menor de edad. La persona menor de edad ejerce sus derechos a través de sus representantes legales.", practicalEffects: ['En la práctica, este artículo rige ejercicio de los derechos por la persona menor de edad. La persona menor de edad ejerce sus derechos a través de sus representantes legales.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ejercicio', 'derechos', 'persona', 'menor', 'edad', 'articulo 26'], segments: [], amendments: [] },
  { id: 'ccyc-art-27', lawId: 'codigo-civil-comercial', number: '27', order: 27, title: "Emancipación", originalText: "Emancipación. La celebración del matrimonio antes de los dieciocho años emancipa a la persona menor de edad. La persona emancipada goza de plena capacidad de ejercicio con las limitaciones previstas en este Código. La emancipación es irrevocable. La nulidad del matrimonio no deja sin efecto la emancipación, excepto respecto del cónyuge de mala fe para quien cesa a partir del día en que la sentencia pasa en autoridad de cosa juzgada. Si algo es debido a la persona menor de edad con cláusula de no poder percibirlo hasta la mayoría de edad, la emancipación no altera la obligación ni el tiempo de su exigibilidad.", currentText: "Emancipación. La celebración del matrimonio antes de los dieciocho años emancipa a la persona menor de edad. La persona emancipada goza de plena capacidad de ejercicio con las limitaciones previstas en este Código. La emancipación es irrevocable. La nulidad del matrimonio no deja sin efecto la emancipación, excepto respecto del cónyuge de mala fe para quien cesa a partir del día en que la sentencia pasa en autoridad de cosa juzgada. Si algo es debido a la persona menor de edad con cláusula de no poder percibirlo hasta la mayoría de edad, la emancipación no altera la obligación ni el tiempo de su exigibilidad.", plainLanguageExplanation: "Establece el régimen de emancipación. La celebración del matrimonio antes de los dieciocho años emancipa a la persona menor de edad.", practicalEffects: ['En la práctica, este artículo rige emancipación. La celebración del matrimonio antes de los dieciocho años emancipa a la persona menor de edad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['emancipacinarticulo 27'], segments: [], amendments: [] },
  { id: 'ccyc-art-28', lawId: 'codigo-civil-comercial', number: '28', order: 28, title: "Actos prohibidos a la persona emancipada", originalText: "Actos prohibidos a la persona emancipada. La persona emancipada no puede, ni con autorización judicial: a) aprobar las cuentas de sus tutores y darles finiquito; b) hacer donación de bienes que hubiese recibido a título gratuito; c) afianzar obligaciones.", currentText: "Actos prohibidos a la persona emancipada. La persona emancipada no puede, ni con autorización judicial: a) aprobar las cuentas de sus tutores y darles finiquito; b) hacer donación de bienes que hubiese recibido a título gratuito; c) afianzar obligaciones.", plainLanguageExplanation: "Establece el régimen de actos prohibidos a la persona emancipada. La persona emancipada no puede, ni con autorización judicial: a) aprobar las cuentas de sus tutores y darles finiquito; b) hacer donación de bienes que hubiese recibido a título gratuito; c) afianzar obligaciones.", practicalEffects: ['En la práctica, este artículo rige actos prohibidos a la persona emancipada. La persona emancipada no puede, ni con autorización judicial: a) aprobar las cuentas de sus tutores y darles finiquito; b) hacer donación de bienes qu'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'prohibidos', 'persona', 'emancipada', 'articulo 28'], segments: [], amendments: [] },
  { id: 'ccyc-art-29', lawId: 'codigo-civil-comercial', number: '29', order: 29, title: "Actos sujetos a autorización judicial", originalText: "Actos sujetos a autorización judicial. El emancipado requiere autorización judicial para disponer de los bienes recibidos a título gratuito. La autorización debe ser otorgada cuando el acto sea de toda necesidad o de ventaja evidente.", currentText: "Actos sujetos a autorización judicial. El emancipado requiere autorización judicial para disponer de los bienes recibidos a título gratuito. La autorización debe ser otorgada cuando el acto sea de toda necesidad o de ventaja evidente.", plainLanguageExplanation: "Establece el régimen de actos sujetos a autorización judicial. El emancipado requiere autorización judicial para disponer de los bienes recibidos a título gratuito.", practicalEffects: ['En la práctica, este artículo rige actos sujetos a autorización judicial. El emancipado requiere autorización judicial para disponer de los bienes recibidos a título gratuito.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'sujetos', 'autorizacin', 'judicial', 'articulo 29'], segments: [], amendments: [] },
  { id: 'ccyc-art-30', lawId: 'codigo-civil-comercial', number: '30', order: 30, title: "Persona menor de edad con título profesional habilitante", originalText: "Persona menor de edad con título profesional habilitante. La persona menor de edad que ha obtenido título habilitante para el ejercicio de una profesión puede ejercerla por cuenta propia sin necesidad de previa autorización. Tiene la administración y disposición de los bienes que adquiere con el producto de su profesión y puede estar en juicio civil o penal por cuestiones vinculadas a ella. SECCION 3ª Restricciones a la capacidad Parágrafo 1° Principios comunes", currentText: "Persona menor de edad con título profesional habilitante. La persona menor de edad que ha obtenido título habilitante para el ejercicio de una profesión puede ejercerla por cuenta propia sin necesidad de previa autorización. Tiene la administración y disposición de los bienes que adquiere con el producto de su profesión y puede estar en juicio civil o penal por cuestiones vinculadas a ella. SECCION 3ª Restricciones a la capacidad Parágrafo 1° Principios comunes", plainLanguageExplanation: "Establece el régimen de persona menor de edad con título profesional habilitante. La persona menor de edad que ha obtenido título habilitante para el ejercicio de una profesión puede ejercerla por cuenta propia sin necesidad de previa autorización.", practicalEffects: ['En la práctica, este artículo rige persona menor de edad con título profesional habilitante. La persona menor de edad que ha obtenido título habilitante para el ejercicio de una profesión puede ejercerla por cuenta propia sin necesidad de previa autorización.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['persona', 'menor', 'edad', 'ttulo', 'profesional', 'habilitante', 'articulo 30'], segments: [], amendments: [] },
  { id: 'ccyc-art-31', lawId: 'codigo-civil-comercial', number: '31', order: 31, title: "Reglas generales", originalText: "Reglas generales. La restricción al ejercicio de la capacidad jurídica se rige por las siguientes reglas generales: a) la capacidad general de ejercicio de la persona humana se presume, aun cuando se encuentre internada en un establecimiento asistencial; b) las limitaciones a la capacidad son de carácter excepcional y se imponen siempre en beneficio de la persona; c) la intervención estatal tiene siempre carácter interdisciplinario, tanto en el tratamiento como en el proceso judicial; d) la persona tiene derecho a recibir información a través de medios y tecnologías adecuadas para su comprensión; e) la persona tiene derecho a participar en el proceso judicial con asistencia letrada, que debe ser proporcionada por el Estado si carece de medios; f) deben priorizarse las alternativas terapéuticas menos restrictivas de los derechos y libertades.", currentText: "Reglas generales. La restricción al ejercicio de la capacidad jurídica se rige por las siguientes reglas generales: a) la capacidad general de ejercicio de la persona humana se presume, aun cuando se encuentre internada en un establecimiento asistencial; b) las limitaciones a la capacidad son de carácter excepcional y se imponen siempre en beneficio de la persona; c) la intervención estatal tiene siempre carácter interdisciplinario, tanto en el tratamiento como en el proceso judicial; d) la persona tiene derecho a recibir información a través de medios y tecnologías adecuadas para su comprensión; e) la persona tiene derecho a participar en el proceso judicial con asistencia letrada, que debe ser proporcionada por el Estado si carece de medios; f) deben priorizarse las alternativas terapéuticas menos restrictivas de los derechos y libertades.", plainLanguageExplanation: "Establece el régimen de reglas generales. La restricción al ejercicio de la capacidad jurídica se rige por las siguientes reglas generales: a) la capacidad general de ejercicio de la persona humana se presume, aun cuando se encuentre internada en un establecimiento asistencial; b) las limitaciones a la capacidad son de c", practicalEffects: ['En la práctica, este artículo rige reglas generales. La restricción al ejercicio de la capacidad jurídica se rige por las siguientes reglas generales: a) la capacidad general de ejercicio de la persona h'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglas', 'generales', 'articulo 31'], segments: [], amendments: [] },
  { id: 'ccyc-art-32', lawId: 'codigo-civil-comercial', number: '32', order: 32, title: "Persona con capacidad restringida y con incapacidad", originalText: "Persona con capacidad restringida y con incapacidad. El juez puede restringir la capacidad para determinados actos de una persona mayor de trece años que padece una adicción o una alteración mental permanente o prolongada, de suficiente gravedad, siempre que estime que del ejercicio de su plena capacidad puede resultar un daño a su persona o a sus bienes. En relación con dichos actos, el juez debe designar el o los apoyos necesarios que prevé el artículo 43, especificando las funciones con los ajustes razonables en función de las necesidades y circunstancias de la persona. El o los apoyos designados deben promover la autonomía y favorecer las decisiones que respondan a las preferencias de la persona protegida. Por excepción, cuando la persona se encuentre absolutamente imposibilitada de interaccionar con su entorno y expresar su voluntad por cualquier modo, medio o formato adecuado y el sistema de apoyos resulte ineficaz, el juez puede declarar la incapacidad y designar un curador.", currentText: "Persona con capacidad restringida y con incapacidad. El juez puede restringir la capacidad para determinados actos de una persona mayor de trece años que padece una adicción o una alteración mental permanente o prolongada, de suficiente gravedad, siempre que estime que del ejercicio de su plena capacidad puede resultar un daño a su persona o a sus bienes. En relación con dichos actos, el juez debe designar el o los apoyos necesarios que prevé el artículo 43, especificando las funciones con los ajustes razonables en función de las necesidades y circunstancias de la persona. El o los apoyos designados deben promover la autonomía y favorecer las decisiones que respondan a las preferencias de la persona protegida. Por excepción, cuando la persona se encuentre absolutamente imposibilitada de interaccionar con su entorno y expresar su voluntad por cualquier modo, medio o formato adecuado y el sistema de apoyos resulte ineficaz, el juez puede declarar la incapacidad y designar un curador.", plainLanguageExplanation: "Establece el régimen de persona con capacidad restringida y con incapacidad. El juez puede restringir la capacidad para determinados actos de una persona mayor de trece años que padece una adicción o una alteración mental permanente o prolongada, de suficiente gravedad, siempre que estime que del ejercicio de su plena capacidad puede resultar un daño a su", practicalEffects: ['En la práctica, este artículo rige persona con capacidad restringida y con incapacidad. El juez puede restringir la capacidad para determinados actos de una persona mayor de trece años que padece una adicción o una alteración mental perma'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['persona', 'capacidad', 'restringida', 'incapacidad', 'articulo 32'], segments: [], amendments: [] },
  { id: 'ccyc-art-33', lawId: 'codigo-civil-comercial', number: '33', order: 33, title: "Legitimados", originalText: "Legitimados. Están legitimados para solicitar la declaración de incapacidad y de capacidad restringida: a) el propio interesado; b) el cónyuge no separado de hecho y el conviviente mientras la convivencia no haya cesado; c) los parientes dentro del cuarto grado; si fueran por afinidad, dentro del segundo grado; d) el Ministerio Público.", currentText: "Legitimados. Están legitimados para solicitar la declaración de incapacidad y de capacidad restringida: a) el propio interesado; b) el cónyuge no separado de hecho y el conviviente mientras la convivencia no haya cesado; c) los parientes dentro del cuarto grado; si fueran por afinidad, dentro del segundo grado; d) el Ministerio Público.", plainLanguageExplanation: "Establece el régimen de legitimados. Están legitimados para solicitar la declaración de incapacidad y de capacidad restringida: a) el propio interesado; b) el cónyuge no separado de hecho y el conviviente mientras la convivencia no haya cesado; c) los parientes dentro del cuarto grado; si fueran por afinidad, dentro", practicalEffects: ['En la práctica, este artículo rige legitimados. Están legitimados para solicitar la declaración de incapacidad y de capacidad restringida: a) el propio interesado; b) el cónyuge no separado de hecho'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legitimadosarticulo 33'], segments: [], amendments: [] },
  { id: 'ccyc-art-34', lawId: 'codigo-civil-comercial', number: '34', order: 34, title: "Medidas cautelares", originalText: "Medidas cautelares. Durante el proceso, el juez debe ordenar las medidas necesarias para garantizar los derechos personales y patrimoniales de la persona. En tal caso, la decisión debe determinar qué actos requieren la asistencia de uno o varios apoyos, y cuáles la representación de un curador. También puede designar redes de apoyo y personas que actúen con funciones específicas según el caso.", currentText: "Medidas cautelares. Durante el proceso, el juez debe ordenar las medidas necesarias para garantizar los derechos personales y patrimoniales de la persona. En tal caso, la decisión debe determinar qué actos requieren la asistencia de uno o varios apoyos, y cuáles la representación de un curador. También puede designar redes de apoyo y personas que actúen con funciones específicas según el caso.", plainLanguageExplanation: "Establece el régimen de medidas cautelares. Durante el proceso, el juez debe ordenar las medidas necesarias para garantizar los derechos personales y patrimoniales de la persona.", practicalEffects: ['En la práctica, este artículo rige medidas cautelares. Durante el proceso, el juez debe ordenar las medidas necesarias para garantizar los derechos personales y patrimoniales de la persona.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medidas', 'cautelares', 'articulo 34'], segments: [], amendments: [] },
  { id: 'ccyc-art-35', lawId: 'codigo-civil-comercial', number: '35', order: 35, title: "Entrevista personal", originalText: "Entrevista personal. El juez debe garantizar la inmediatez con el interesado durante el proceso y entrevistarlo personalmente antes de dictar resolución alguna, asegurando la accesibilidad y los ajustes razonables del procedimiento de acuerdo a la situación de aquél. El Ministerio Público y, al menos, un letrado que preste asistencia al interesado, deben estar presentes en las audiencias.", currentText: "Entrevista personal. El juez debe garantizar la inmediatez con el interesado durante el proceso y entrevistarlo personalmente antes de dictar resolución alguna, asegurando la accesibilidad y los ajustes razonables del procedimiento de acuerdo a la situación de aquél. El Ministerio Público y, al menos, un letrado que preste asistencia al interesado, deben estar presentes en las audiencias.", plainLanguageExplanation: "Establece el régimen de entrevista personal. El juez debe garantizar la inmediatez con el interesado durante el proceso y entrevistarlo personalmente antes de dictar resolución alguna, asegurando la accesibilidad y los ajustes razonables del procedimiento de acuerdo a la situación de aquél.", practicalEffects: ['En la práctica, este artículo rige entrevista personal. El juez debe garantizar la inmediatez con el interesado durante el proceso y entrevistarlo personalmente antes de dictar resolución alguna, asegurando'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['entrevista', 'personal', 'articulo 35'], segments: [], amendments: [] },
  { id: 'ccyc-art-36', lawId: 'codigo-civil-comercial', number: '36', order: 36, title: "Intervención del interesado en el proceso", originalText: "Intervención del interesado en el proceso. Competencia. La persona en cuyo interés se lleva adelante el proceso es parte y puede aportar todas las pruebas que hacen a su defensa. Interpuesta la solicitud de declaración de incapacidad o de restricción de la capacidad ante el juez correspondiente a su domicilio o del lugar de su internación, si la persona en cuyo interés se lleva adelante el proceso ha comparecido sin abogado, se le debe nombrar uno para que la represente y le preste asistencia letrada en el juicio. La persona que solicitó la declaración puede aportar toda clase de pruebas para acreditar los hechos invocados.", currentText: "Intervención del interesado en el proceso. Competencia. La persona en cuyo interés se lleva adelante el proceso es parte y puede aportar todas las pruebas que hacen a su defensa. Interpuesta la solicitud de declaración de incapacidad o de restricción de la capacidad ante el juez correspondiente a su domicilio o del lugar de su internación, si la persona en cuyo interés se lleva adelante el proceso ha comparecido sin abogado, se le debe nombrar uno para que la represente y le preste asistencia letrada en el juicio. La persona que solicitó la declaración puede aportar toda clase de pruebas para acreditar los hechos invocados.", plainLanguageExplanation: "Establece el régimen de intervención del interesado en el proceso. Competencia.", practicalEffects: ['En la práctica, este artículo rige intervención del interesado en el proceso. Competencia.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['intervencin', 'interesado', 'proceso', 'articulo 36'], segments: [], amendments: [] },
  { id: 'ccyc-art-37', lawId: 'codigo-civil-comercial', number: '37', order: 37, title: "Sentencia", originalText: "Sentencia. La sentencia se debe pronunciar sobre los siguientes aspectos vinculados a la persona en cuyo interés se sigue el proceso: a) diagnóstico y pronóstico; b) época en que la situación se manifestó; c) recursos personales, familiares y sociales existentes; d) régimen para la protección, asistencia y promoción de la mayor autonomía posible. Para expedirse, es imprescindible el dictamen de un equipo interdisciplinario.", currentText: "Sentencia. La sentencia se debe pronunciar sobre los siguientes aspectos vinculados a la persona en cuyo interés se sigue el proceso: a) diagnóstico y pronóstico; b) época en que la situación se manifestó; c) recursos personales, familiares y sociales existentes; d) régimen para la protección, asistencia y promoción de la mayor autonomía posible. Para expedirse, es imprescindible el dictamen de un equipo interdisciplinario.", plainLanguageExplanation: "Establece el régimen de sentencia. La sentencia se debe pronunciar sobre los siguientes aspectos vinculados a la persona en cuyo interés se sigue el proceso: a) diagnóstico y pronóstico; b) época en que la situación se manifestó; c) recursos personales, familiares y sociales existentes; d) régimen para la protecci", practicalEffects: ['En la práctica, este artículo rige sentencia. La sentencia se debe pronunciar sobre los siguientes aspectos vinculados a la persona en cuyo interés se sigue el proceso: a) diagnóstico y pronóstico'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sentenciaarticulo 37'], segments: [], amendments: [] },
  { id: 'ccyc-art-38', lawId: 'codigo-civil-comercial', number: '38', order: 38, title: "Alcances de la sentencia", originalText: "Alcances de la sentencia. La sentencia debe determinar la extensión y alcance de la restricción y especificar las funciones y actos que se limitan, procurando que la afectación de la autonomía personal sea la menor posible. Asimismo, debe designar una o más personas de apoyo o curadores de acuerdo a lo establecido en el artículo 32 de este Código y señalar las condiciones de validez de los actos específicos sujetos a la restricción con indicación de la o las personas intervinientes y la modalidad de su actuación.", currentText: "Alcances de la sentencia. La sentencia debe determinar la extensión y alcance de la restricción y especificar las funciones y actos que se limitan, procurando que la afectación de la autonomía personal sea la menor posible. Asimismo, debe designar una o más personas de apoyo o curadores de acuerdo a lo establecido en el artículo 32 de este Código y señalar las condiciones de validez de los actos específicos sujetos a la restricción con indicación de la o las personas intervinientes y la modalidad de su actuación.", plainLanguageExplanation: "Establece el régimen de alcances de la sentencia. La sentencia debe determinar la extensión y alcance de la restricción y especificar las funciones y actos que se limitan, procurando que la afectación de la autonomía personal sea la menor posible.", practicalEffects: ['En la práctica, este artículo rige alcances de la sentencia. La sentencia debe determinar la extensión y alcance de la restricción y especificar las funciones y actos que se limitan, procurando que la afectación de la autonomía personal sea la menor posible.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['alcances', 'sentencia', 'articulo 38'], segments: [], amendments: [] },
  { id: 'ccyc-art-39', lawId: 'codigo-civil-comercial', number: '39', order: 39, title: "Registración de la sentencia", originalText: "Registración de la sentencia. La sentencia debe ser inscripta en el Registro de Estado Civil y Capacidad de las Personas y se debe dejar constancia al margen del acta de nacimiento. Sin perjuicio de lo dispuesto en el artículo 45, los actos mencionados en este Capítulo producen efectos contra terceros recién a partir de la fecha de inscripción en el registro. Desaparecidas las restricciones, se procede a la inmediata cancelación registral.", currentText: "Registración de la sentencia. La sentencia debe ser inscripta en el Registro de Estado Civil y Capacidad de las Personas y se debe dejar constancia al margen del acta de nacimiento. Sin perjuicio de lo dispuesto en el artículo 45, los actos mencionados en este Capítulo producen efectos contra terceros recién a partir de la fecha de inscripción en el registro. Desaparecidas las restricciones, se procede a la inmediata cancelación registral.", plainLanguageExplanation: "Establece el régimen de registración de la sentencia. La sentencia debe ser inscripta en el Registro de Estado Civil y Capacidad de las Personas y se debe dejar constancia al margen del acta de nacimiento.", practicalEffects: ['En la práctica, este artículo rige registración de la sentencia. La sentencia debe ser inscripta en el Registro de Estado Civil y Capacidad de las Personas y se debe dejar constancia al margen del acta de nacimiento.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['registracin', 'sentencia', 'articulo 39'], segments: [], amendments: [] },
  { id: 'ccyc-art-40', lawId: 'codigo-civil-comercial', number: '40', order: 40, title: "Revisión", originalText: "Revisión. La revisión de la sentencia declarativa puede tener lugar en cualquier momento, a instancias del interesado. En el supuesto previsto en el artículo 32, la sentencia debe ser revisada por el juez en un plazo no superior a tres años, sobre la base de nuevos dictámenes interdisciplinarios y mediando la audiencia personal con el interesado. Es deber del Ministerio Público fiscalizar el cumplimiento efectivo de la revisión judicial a que refiere el párrafo primero e instar, en su caso, a que ésta se lleve a cabo si el juez no la hubiere efectuado en el plazo allí establecido.", currentText: "Revisión. La revisión de la sentencia declarativa puede tener lugar en cualquier momento, a instancias del interesado. En el supuesto previsto en el artículo 32, la sentencia debe ser revisada por el juez en un plazo no superior a tres años, sobre la base de nuevos dictámenes interdisciplinarios y mediando la audiencia personal con el interesado. Es deber del Ministerio Público fiscalizar el cumplimiento efectivo de la revisión judicial a que refiere el párrafo primero e instar, en su caso, a que ésta se lleve a cabo si el juez no la hubiere efectuado en el plazo allí establecido.", plainLanguageExplanation: "Establece el régimen de revisión. La revisión de la sentencia declarativa puede tener lugar en cualquier momento, a instancias del interesado.", practicalEffects: ['En la práctica, este artículo rige revisión. La revisión de la sentencia declarativa puede tener lugar en cualquier momento, a instancias del interesado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['revisinarticulo 40'], segments: [], amendments: [] },
  { id: 'ccyc-art-41', lawId: 'codigo-civil-comercial', number: '41', order: 41, title: "Internación", originalText: "Internación. La internación sin consentimiento de una persona, tenga o no restringida su capacidad, procede sólo si se cumplen los recaudos previstos en la legislación especial y las reglas generales de esta Sección. En particular: a) debe estar fundada en una evaluación de un equipo interdisciplinario de acuerdo a lo dispuesto en el artículo 37, que señale los motivos que la justifican y la ausencia de una alternativa eficaz menos restrictiva de su libertad; b) sólo procede ante la existencia de riesgo cierto e inminente de un daño de entidad para la persona protegida o para terceros; c) es considerada un recurso terapéutico de carácter restrictivo y por el tiempo más breve posible; debe ser supervisada periódicamente; d) debe garantizarse el debido proceso, el control judicial inmediato y el derecho de defensa mediante asistencia jurídica; e) la sentencia que aprueba la internación debe especificar su finalidad, duración y periodicidad de la revisión. Toda persona con padecimientos mentales, se encuentre o no internada, goza de los derechos fundamentales y sus extensiones.", currentText: "Internación. La internación sin consentimiento de una persona, tenga o no restringida su capacidad, procede sólo si se cumplen los recaudos previstos en la legislación especial y las reglas generales de esta Sección. En particular: a) debe estar fundada en una evaluación de un equipo interdisciplinario de acuerdo a lo dispuesto en el artículo 37, que señale los motivos que la justifican y la ausencia de una alternativa eficaz menos restrictiva de su libertad; b) sólo procede ante la existencia de riesgo cierto e inminente de un daño de entidad para la persona protegida o para terceros; c) es considerada un recurso terapéutico de carácter restrictivo y por el tiempo más breve posible; debe ser supervisada periódicamente; d) debe garantizarse el debido proceso, el control judicial inmediato y el derecho de defensa mediante asistencia jurídica; e) la sentencia que aprueba la internación debe especificar su finalidad, duración y periodicidad de la revisión. Toda persona con padecimientos mentales, se encuentre o no internada, goza de los derechos fundamentales y sus extensiones.", plainLanguageExplanation: "Establece el régimen de internación. La internación sin consentimiento de una persona, tenga o no restringida su capacidad, procede sólo si se cumplen los recaudos previstos en la legislación especial y las reglas generales de esta Sección.", practicalEffects: ['En la práctica, este artículo rige internación. La internación sin consentimiento de una persona, tenga o no restringida su capacidad, procede sólo si se cumplen los recaudos previstos en la legisla'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['internacinarticulo 41'], segments: [], amendments: [] },
  { id: 'ccyc-art-42', lawId: 'codigo-civil-comercial', number: '42', order: 42, title: "Traslado dispuesto por autoridad pública", originalText: "Traslado dispuesto por autoridad pública. Evaluación e internación. La autoridad pública puede disponer el traslado de una persona cuyo estado no admita dilaciones y se encuentre en riesgo cierto e inminente de daño para sí o para terceros, a un centro de salud para su evaluación. En este caso, si fuese admitida la internación, debe cumplirse con los plazos y modalidades establecidos en la legislación especial. Las fuerzas de seguridad y servicios públicos de salud deben prestar auxilio inmediato. Parágrafo 2° Sistemas de apoyo al ejercicio de la capacidad", currentText: "Traslado dispuesto por autoridad pública. Evaluación e internación. La autoridad pública puede disponer el traslado de una persona cuyo estado no admita dilaciones y se encuentre en riesgo cierto e inminente de daño para sí o para terceros, a un centro de salud para su evaluación. En este caso, si fuese admitida la internación, debe cumplirse con los plazos y modalidades establecidos en la legislación especial. Las fuerzas de seguridad y servicios públicos de salud deben prestar auxilio inmediato. Parágrafo 2° Sistemas de apoyo al ejercicio de la capacidad", plainLanguageExplanation: "Establece el régimen de traslado dispuesto por autoridad pública. Evaluación e internación.", practicalEffects: ['En la práctica, este artículo rige traslado dispuesto por autoridad pública. Evaluación e internación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['traslado', 'dispuesto', 'autoridad', 'pblica', 'articulo 42'], segments: [], amendments: [] },
  { id: 'ccyc-art-43', lawId: 'codigo-civil-comercial', number: '43', order: 43, title: "Concepto", originalText: "Concepto. Función. Designación. Se entiende por apoyo cualquier medida de carácter judicial o extrajudicial que facilite a la persona que lo necesite la toma de decisiones para dirigir su persona, administrar sus bienes y celebrar actos jurídicos en general. Las medidas de apoyo tienen como función la de promover la autonomía y facilitar la comunicación, la comprensión y la manifestación de voluntad de la persona para el ejercicio de sus derechos. El interesado puede proponer al juez la designación de una o más personas de su confianza para que le presten apoyo. El juez debe evaluar los alcances de la designación y procurar la protección de la persona respecto de eventuales conflictos de intereses o influencia indebida. La resolución debe establecer la condición y la calidad de las medidas de apoyo y, de ser necesario, ser inscripta en el Registro de Estado Civil y Capacidad de las Personas. Parágrafo 3° Actos realizados por persona incapaz o con capacidad restringida", currentText: "Concepto. Función. Designación. Se entiende por apoyo cualquier medida de carácter judicial o extrajudicial que facilite a la persona que lo necesite la toma de decisiones para dirigir su persona, administrar sus bienes y celebrar actos jurídicos en general. Las medidas de apoyo tienen como función la de promover la autonomía y facilitar la comunicación, la comprensión y la manifestación de voluntad de la persona para el ejercicio de sus derechos. El interesado puede proponer al juez la designación de una o más personas de su confianza para que le presten apoyo. El juez debe evaluar los alcances de la designación y procurar la protección de la persona respecto de eventuales conflictos de intereses o influencia indebida. La resolución debe establecer la condición y la calidad de las medidas de apoyo y, de ser necesario, ser inscripta en el Registro de Estado Civil y Capacidad de las Personas. Parágrafo 3° Actos realizados por persona incapaz o con capacidad restringida", plainLanguageExplanation: "Establece el régimen de concepto. Función.", practicalEffects: ['En la práctica, este artículo rige concepto. Función.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conceptoarticulo 43'], segments: [], amendments: [] },
  { id: 'ccyc-art-44', lawId: 'codigo-civil-comercial', number: '44', order: 44, title: "Actos posteriores a la inscripción de la sentencia", originalText: "Actos posteriores a la inscripción de la sentencia. Son nulos los actos de la persona incapaz y con capacidad restringida que contrarían lo dispuesto en la sentencia realizados con posterioridad a su inscripción en el Registro de Estado Civil y Capacidad de las Personas.", currentText: "Actos posteriores a la inscripción de la sentencia. Son nulos los actos de la persona incapaz y con capacidad restringida que contrarían lo dispuesto en la sentencia realizados con posterioridad a su inscripción en el Registro de Estado Civil y Capacidad de las Personas.", plainLanguageExplanation: "Establece el régimen de actos posteriores a la inscripción de la sentencia. Son nulos los actos de la persona incapaz y con capacidad restringida que contrarían lo dispuesto en la sentencia realizados con posterioridad a su inscripción en el Registro de Estado Civil y Capacidad de las Personas.", practicalEffects: ['En la práctica, este artículo rige actos posteriores a la inscripción de la sentencia. Son nulos los actos de la persona incapaz y con capacidad restringida que contrarían lo dispuesto en la sentencia realizados con posterioridad a su in'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'posteriores', 'inscripcin', 'sentencia', 'articulo 44'], segments: [], amendments: [] },
  { id: 'ccyc-art-45', lawId: 'codigo-civil-comercial', number: '45', order: 45, title: "Actos anteriores a la inscripción", originalText: "Actos anteriores a la inscripción. Los actos anteriores a la inscripción de la sentencia pueden ser declarados nulos, si perjudican a la persona incapaz o con capacidad restringida, y se cumple alguno de los siguientes extremos: a) la enfermedad mental era ostensible a la época de la celebración del acto; b) quien contrató con él era de mala fe; c) el acto es a título gratuito.", currentText: "Actos anteriores a la inscripción. Los actos anteriores a la inscripción de la sentencia pueden ser declarados nulos, si perjudican a la persona incapaz o con capacidad restringida, y se cumple alguno de los siguientes extremos: a) la enfermedad mental era ostensible a la época de la celebración del acto; b) quien contrató con él era de mala fe; c) el acto es a título gratuito.", plainLanguageExplanation: "Establece el régimen de actos anteriores a la inscripción. Los actos anteriores a la inscripción de la sentencia pueden ser declarados nulos, si perjudican a la persona incapaz o con capacidad restringida, y se cumple alguno de los siguientes extremos: a) la enfermedad mental era ostensible a la época de la celebración del acto; b) quien", practicalEffects: ['En la práctica, este artículo rige actos anteriores a la inscripción. Los actos anteriores a la inscripción de la sentencia pueden ser declarados nulos, si perjudican a la persona incapaz o con capacidad restringida, y s'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'anteriores', 'inscripcin', 'articulo 45'], segments: [], amendments: [] },
  { id: 'ccyc-art-46', lawId: 'codigo-civil-comercial', number: '46', order: 46, title: "Persona fallecida", originalText: "Persona fallecida. Luego de su fallecimiento, los actos entre vivos anteriores a la inscripción de la sentencia no pueden impugnarse, excepto que la enfermedad mental resulte del acto mismo, que la muerte haya acontecido después de promovida la acción para la declaración de incapacidad o capacidad restringida, que el acto sea a título gratuito, o que se pruebe que quien contrató con ella actuó de mala fe. Parágrafo 4° Cese de la incapacidad y de las restricciones a la capacidad", currentText: "Persona fallecida. Luego de su fallecimiento, los actos entre vivos anteriores a la inscripción de la sentencia no pueden impugnarse, excepto que la enfermedad mental resulte del acto mismo, que la muerte haya acontecido después de promovida la acción para la declaración de incapacidad o capacidad restringida, que el acto sea a título gratuito, o que se pruebe que quien contrató con ella actuó de mala fe. Parágrafo 4° Cese de la incapacidad y de las restricciones a la capacidad", plainLanguageExplanation: "Establece el régimen de persona fallecida. Luego de su fallecimiento, los actos entre vivos anteriores a la inscripción de la sentencia no pueden impugnarse, excepto que la enfermedad mental resulte del acto mismo, que la muerte haya acontecido después de promovida la acción para la declaración de incapacidad o capacidad", practicalEffects: ['En la práctica, este artículo rige persona fallecida. Luego de su fallecimiento, los actos entre vivos anteriores a la inscripción de la sentencia no pueden impugnarse, excepto que la enfermedad mental re'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['persona', 'fallecida', 'articulo 46'], segments: [], amendments: [] },
  { id: 'ccyc-art-47', lawId: 'codigo-civil-comercial', number: '47', order: 47, title: "Procedimiento para el cese", originalText: "Procedimiento para el cese. El cese de la incapacidad o de la restricción a la capacidad debe decretarse por el juez que la declaró, previo examen de un equipo interdisciplinario integrado conforme a las pautas del artículo 37, que dictamine sobre el restablecimiento de la persona. Si el restablecimiento no es total, el juez puede ampliar la nómina de actos que la persona puede realizar por sí o con la asistencia de su curador o apoyo. Parágrafo 5° Inhabilitados", currentText: "Procedimiento para el cese. El cese de la incapacidad o de la restricción a la capacidad debe decretarse por el juez que la declaró, previo examen de un equipo interdisciplinario integrado conforme a las pautas del artículo 37, que dictamine sobre el restablecimiento de la persona. Si el restablecimiento no es total, el juez puede ampliar la nómina de actos que la persona puede realizar por sí o con la asistencia de su curador o apoyo. Parágrafo 5° Inhabilitados", plainLanguageExplanation: "Establece el régimen de procedimiento para el cese. El cese de la incapacidad o de la restricción a la capacidad debe decretarse por el juez que la declaró, previo examen de un equipo interdisciplinario integrado conforme a las pautas del artículo 37, que dictamine sobre el restablecimiento de la persona.", practicalEffects: ['En la práctica, este artículo rige procedimiento para el cese. El cese de la incapacidad o de la restricción a la capacidad debe decretarse por el juez que la declaró, previo examen de un equipo interdisciplinario'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['procedimiento', 'para', 'cese', 'articulo 47'], segments: [], amendments: [] },
  { id: 'ccyc-art-48', lawId: 'codigo-civil-comercial', number: '48', order: 48, title: "Pródigos", originalText: "Pródigos. Pueden ser inhabilitados quienes por la prodigalidad en la gestión de sus bienes expongan a su cónyuge, conviviente o a sus hijos menores de edad o con discapacidad a la pérdida del patrimonio. A estos fines, se considera persona con discapacidad, a toda persona que padece una alteración funcional permanente o prolongada, física o mental, que en relación a su edad y medio social implica desventajas considerables para su integración familiar, social, educacional o laboral. La acción sólo corresponde al cónyuge, conviviente y a los ascendientes y descendientes.", currentText: "Pródigos. Pueden ser inhabilitados quienes por la prodigalidad en la gestión de sus bienes expongan a su cónyuge, conviviente o a sus hijos menores de edad o con discapacidad a la pérdida del patrimonio. A estos fines, se considera persona con discapacidad, a toda persona que padece una alteración funcional permanente o prolongada, física o mental, que en relación a su edad y medio social implica desventajas considerables para su integración familiar, social, educacional o laboral. La acción sólo corresponde al cónyuge, conviviente y a los ascendientes y descendientes.", plainLanguageExplanation: "Establece el régimen de pródigos. Pueden ser inhabilitados quienes por la prodigalidad en la gestión de sus bienes expongan a su cónyuge, conviviente o a sus hijos menores de edad o con discapacidad a la pérdida del patrimonio.", practicalEffects: ['En la práctica, este artículo rige pródigos. Pueden ser inhabilitados quienes por la prodigalidad en la gestión de sus bienes expongan a su cónyuge, conviviente o a sus hijos menores de edad o con discapacidad a la pérdida del patrimonio.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prdigosarticulo 48'], segments: [], amendments: [] },
  { id: 'ccyc-art-49', lawId: 'codigo-civil-comercial', number: '49', order: 49, title: "Efectos", originalText: "Efectos. La declaración de inhabilitación importa la designación de un apoyo, que debe asistir al inhabilitado en el otorgamiento de actos de disposición entre vivos y en los demás actos que el juez fije en la sentencia.", currentText: "Efectos. La declaración de inhabilitación importa la designación de un apoyo, que debe asistir al inhabilitado en el otorgamiento de actos de disposición entre vivos y en los demás actos que el juez fije en la sentencia.", plainLanguageExplanation: "Establece el régimen de efectos. La declaración de inhabilitación importa la designación de un apoyo, que debe asistir al inhabilitado en el otorgamiento de actos de disposición entre vivos y en los demás actos que el juez fije en la sentencia.", practicalEffects: ['En la práctica, este artículo rige efectos. La declaración de inhabilitación importa la designación de un apoyo, que debe asistir al inhabilitado en el otorgamiento de actos de disposición entre'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 49'], segments: [], amendments: [] },
  { id: 'ccyc-art-50', lawId: 'codigo-civil-comercial', number: '50', order: 50, title: "Cese de la inhabilitación", originalText: "Cese de la inhabilitación. El cese de la inhabilitación se decreta por el juez que la declaró, previo examen interdisciplinario que dictamine sobre el restablecimiento de la persona. Si el restablecimiento no es total, el juez puede ampliar la nómina de actos que la persona puede realizar por sí o con apoyo. CAPITULO 3 Derechos y actos personalísimos", currentText: "Cese de la inhabilitación. El cese de la inhabilitación se decreta por el juez que la declaró, previo examen interdisciplinario que dictamine sobre el restablecimiento de la persona. Si el restablecimiento no es total, el juez puede ampliar la nómina de actos que la persona puede realizar por sí o con apoyo. CAPITULO 3 Derechos y actos personalísimos", plainLanguageExplanation: "Establece el régimen de cese de la inhabilitación. El cese de la inhabilitación se decreta por el juez que la declaró, previo examen interdisciplinario que dictamine sobre el restablecimiento de la persona.", practicalEffects: ['En la práctica, este artículo rige cese de la inhabilitación. El cese de la inhabilitación se decreta por el juez que la declaró, previo examen interdisciplinario que dictamine sobre el restablecimiento de la persona.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cese', 'inhabilitacin', 'articulo 50'], segments: [], amendments: [] },
  { id: 'ccyc-art-51', lawId: 'codigo-civil-comercial', number: '51', order: 51, title: "Inviolabilidad de la persona humana", originalText: "Inviolabilidad de la persona humana. La persona humana es inviolable y en cualquier circunstancia tiene derecho al reconocimiento y respeto de su dignidad.", currentText: "Inviolabilidad de la persona humana. La persona humana es inviolable y en cualquier circunstancia tiene derecho al reconocimiento y respeto de su dignidad.", plainLanguageExplanation: "Establece el régimen de inviolabilidad de la persona humana. La persona humana es inviolable y en cualquier circunstancia tiene derecho al reconocimiento y respeto de su dignidad.", practicalEffects: ['En la práctica, este artículo rige inviolabilidad de la persona humana. La persona humana es inviolable y en cualquier circunstancia tiene derecho al reconocimiento y respeto de su dignidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inviolabilidad', 'persona', 'humana', 'articulo 51'], segments: [], amendments: [] },
  { id: 'ccyc-art-52', lawId: 'codigo-civil-comercial', number: '52', order: 52, title: "Afectaciones a la dignidad", originalText: "Afectaciones a la dignidad. La persona humana lesionada en su intimidad personal o familiar, honra o reputación, imagen o identidad, o que de cualquier modo resulte menoscabada en su dignidad personal, puede reclamar la prevención y reparación de los daños sufridos, conforme a lo dispuesto en el Libro Tercero, Título V, Capítulo 1.", currentText: "Afectaciones a la dignidad. La persona humana lesionada en su intimidad personal o familiar, honra o reputación, imagen o identidad, o que de cualquier modo resulte menoscabada en su dignidad personal, puede reclamar la prevención y reparación de los daños sufridos, conforme a lo dispuesto en el Libro Tercero, Título V, Capítulo 1.", plainLanguageExplanation: "Establece el régimen de afectaciones a la dignidad. La persona humana lesionada en su intimidad personal o familiar, honra o reputación, imagen o identidad, o que de cualquier modo resulte menoscabada en su dignidad personal, puede reclamar la prevención y reparación de los daños sufridos, conforme a lo dispuesto en el Libro Terce", practicalEffects: ['En la práctica, este artículo rige afectaciones a la dignidad. La persona humana lesionada en su intimidad personal o familiar, honra o reputación, imagen o identidad, o que de cualquier modo resulte menoscabada e'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['afectaciones', 'dignidad', 'articulo 52'], segments: [], amendments: [] },
  { id: 'ccyc-art-53', lawId: 'codigo-civil-comercial', number: '53', order: 53, title: "Derecho a la imagen", originalText: "Derecho a la imagen. Para captar o reproducir la imagen o la voz de una persona, de cualquier modo que se haga, es necesario su consentimiento, excepto en los siguientes casos: a) que la persona participe en actos públicos; b) que exista un interés científico, cultural o educacional prioritario, y se tomen las precauciones suficientes para evitar un daño innecesario; c) que se trate del ejercicio regular del derecho de informar sobre acontecimientos de interés general. En caso de personas fallecidas pueden prestar el consentimiento sus herederos o el designado por el causante en una disposición de última voluntad. Si hay desacuerdo entre herederos de un mismo grado, resuelve el juez. Pasados veinte años desde la muerte, la reproducción no ofensiva es libre.", currentText: "Derecho a la imagen. Para captar o reproducir la imagen o la voz de una persona, de cualquier modo que se haga, es necesario su consentimiento, excepto en los siguientes casos: a) que la persona participe en actos públicos; b) que exista un interés científico, cultural o educacional prioritario, y se tomen las precauciones suficientes para evitar un daño innecesario; c) que se trate del ejercicio regular del derecho de informar sobre acontecimientos de interés general. En caso de personas fallecidas pueden prestar el consentimiento sus herederos o el designado por el causante en una disposición de última voluntad. Si hay desacuerdo entre herederos de un mismo grado, resuelve el juez. Pasados veinte años desde la muerte, la reproducción no ofensiva es libre.", plainLanguageExplanation: "Establece el régimen de derecho a la imagen. Para captar o reproducir la imagen o la voz de una persona, de cualquier modo que se haga, es necesario su consentimiento, excepto en los siguientes casos: a) que la persona participe en actos públicos; b) que exista un interés científico, cultural o educacional prioritario, y se", practicalEffects: ['En la práctica, este artículo rige derecho a la imagen. Para captar o reproducir la imagen o la voz de una persona, de cualquier modo que se haga, es necesario su consentimiento, excepto en los siguientes c'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'imagen', 'articulo 53'], segments: [], amendments: [] },
  { id: 'ccyc-art-54', lawId: 'codigo-civil-comercial', number: '54', order: 54, title: "Actos peligrosos", originalText: "Actos peligrosos. No es exigible el cumplimiento del contrato que tiene por objeto la realización de actos peligrosos para la vida o la integridad de una persona, excepto que correspondan a su actividad habitual y que se adopten las medidas de prevención y seguridad adecuadas a las circunstancias.", currentText: "Actos peligrosos. No es exigible el cumplimiento del contrato que tiene por objeto la realización de actos peligrosos para la vida o la integridad de una persona, excepto que correspondan a su actividad habitual y que se adopten las medidas de prevención y seguridad adecuadas a las circunstancias.", plainLanguageExplanation: "Establece el régimen de actos peligrosos. No es exigible el cumplimiento del contrato que tiene por objeto la realización de actos peligrosos para la vida o la integridad de una persona, excepto que correspondan a su actividad habitual y que se adopten las medidas de prevención y seguridad adecuadas a las circunstancias.", practicalEffects: ['En la práctica, este artículo rige actos peligrosos. No es exigible el cumplimiento del contrato que tiene por objeto la realización de actos peligrosos para la vida o la integridad de una persona, excep'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'peligrosos', 'articulo 54'], segments: [], amendments: [] },
  { id: 'ccyc-art-55', lawId: 'codigo-civil-comercial', number: '55', order: 55, title: "Disposición de derechos personalísimos", originalText: "Disposición de derechos personalísimos. El consentimiento para la disposición de los derechos personalísimos es admitido si no es contrario a la ley, la moral o las buenas costumbres. Este consentimiento no se presume, es de interpretación restrictiva, y libremente revocable.", currentText: "Disposición de derechos personalísimos. El consentimiento para la disposición de los derechos personalísimos es admitido si no es contrario a la ley, la moral o las buenas costumbres. Este consentimiento no se presume, es de interpretación restrictiva, y libremente revocable.", plainLanguageExplanation: "Establece el régimen de disposición de derechos personalísimos. El consentimiento para la disposición de los derechos personalísimos es admitido si no es contrario a la ley, la moral o las buenas costumbres.", practicalEffects: ['En la práctica, este artículo rige disposición de derechos personalísimos. El consentimiento para la disposición de los derechos personalísimos es admitido si no es contrario a la ley, la moral o las buenas costumbres.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['disposicin', 'derechos', 'personalsimos', 'articulo 55'], segments: [], amendments: [] },
  { id: 'ccyc-art-56', lawId: 'codigo-civil-comercial', number: '56', order: 56, title: "Actos de disposición sobre el propio cuerpo", originalText: "Actos de disposición sobre el propio cuerpo. Están prohibidos los actos de disposición del propio cuerpo que ocasionen una disminución permanente de su integridad o resulten contrarios a la ley, la moral o las buenas costumbres, excepto que sean requeridos para el mejoramiento de la salud de la persona, y excepcionalmente de otra persona, de conformidad a lo dispuesto en el ordenamiento jurídico. La ablación de órganos para ser implantados en otras personas se rige por la legislación especial. El consentimiento para los actos no comprendidos en la prohibición establecida en el primer párrafo no puede ser suplido, y es libremente revocable.", currentText: "Actos de disposición sobre el propio cuerpo. Están prohibidos los actos de disposición del propio cuerpo que ocasionen una disminución permanente de su integridad o resulten contrarios a la ley, la moral o las buenas costumbres, excepto que sean requeridos para el mejoramiento de la salud de la persona, y excepcionalmente de otra persona, de conformidad a lo dispuesto en el ordenamiento jurídico. La ablación de órganos para ser implantados en otras personas se rige por la legislación especial. El consentimiento para los actos no comprendidos en la prohibición establecida en el primer párrafo no puede ser suplido, y es libremente revocable.", plainLanguageExplanation: "Establece el régimen de actos de disposición sobre el propio cuerpo. Están prohibidos los actos de disposición del propio cuerpo que ocasionen una disminución permanente de su integridad o resulten contrarios a la ley, la moral o las buenas costumbres, excepto que sean requeridos para el mejoramiento de la salud de la persona, y excepcionalmente d", practicalEffects: ['En la práctica, este artículo rige actos de disposición sobre el propio cuerpo. Están prohibidos los actos de disposición del propio cuerpo que ocasionen una disminución permanente de su integridad o resulten contrarios a la ley,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'disposicin', 'sobre', 'propio', 'cuerpo', 'articulo 56'], segments: [], amendments: [] },
  { id: 'ccyc-art-57', lawId: 'codigo-civil-comercial', number: '57', order: 57, title: "Prácticas prohibidas", originalText: "Prácticas prohibidas. Está prohibida toda práctica destinada a producir una alteración genética del embrión que se transmita a su descendencia.", currentText: "Prácticas prohibidas. Está prohibida toda práctica destinada a producir una alteración genética del embrión que se transmita a su descendencia.", plainLanguageExplanation: "Establece el régimen de prácticas prohibidas. Está prohibida toda práctica destinada a producir una alteración genética del embrión que se transmita a su descendencia.", practicalEffects: ['En la práctica, este artículo rige prácticas prohibidas. Está prohibida toda práctica destinada a producir una alteración genética del embrión que se transmita a su descendencia.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prcticas', 'prohibidas', 'articulo 57'], segments: [], amendments: [] },
  { id: 'ccyc-art-58', lawId: 'codigo-civil-comercial', number: '58', order: 58, title: "Investigaciones en seres humanos", originalText: "Investigaciones en seres humanos. La investigación médica en seres humanos mediante intervenciones, tales como tratamientos, métodos de prevención, pruebas diagnósticas o predictivas, cuya eficacia o seguridad no están comprobadas científicamente, sólo puede ser realizada si se cumple con los siguientes requisitos: a) describir claramente el proyecto y el método que se aplicará en un protocolo de investigación; b) ser realizada por personas con la formación y calificaciones científicas y profesionales apropiadas; c) contar con la aprobación previa de un comité acreditado de evaluación de ética en la investigación; d) contar con la autorización previa del organismo público correspondiente; e) estar fundamentada en una cuidadosa comparación de los riesgos y las cargas en relación con los beneficios previsibles que representan para las personas que participan en la investigación y para otras personas afectadas por el tema que se investiga; f) contar con el consentimiento previo, libre, escrito, informado y específico de la persona que participa en la investigación, a quien se le debe explicar, en términos comprensibles, los objetivos y la metodología de la investigación, sus riesgos y posibles beneficios; dicho consentimiento es revocable; g) no implicar para el participante riesgos y molestias desproporcionados en relación con los beneficios que se espera obtener de la investigación; h) resguardar la intimidad de la persona que participa en la investigación y la confidencialidad de su información personal; i) asegurar que la participación de los sujetos de la investigación no les resulte onerosa a éstos y que tengan acceso a la atención médica apropiada en caso de eventos adversos relacionados con la investigación, la que debe estar disponible cuando sea requerida; j) asegurar a los participantes de la investigación la disponibilidad y accesibilidad a los tratamientos que la investigación haya demostrado beneficiosos.", currentText: "Investigaciones en seres humanos. La investigación médica en seres humanos mediante intervenciones, tales como tratamientos, métodos de prevención, pruebas diagnósticas o predictivas, cuya eficacia o seguridad no están comprobadas científicamente, sólo puede ser realizada si se cumple con los siguientes requisitos: a) describir claramente el proyecto y el método que se aplicará en un protocolo de investigación; b) ser realizada por personas con la formación y calificaciones científicas y profesionales apropiadas; c) contar con la aprobación previa de un comité acreditado de evaluación de ética en la investigación; d) contar con la autorización previa del organismo público correspondiente; e) estar fundamentada en una cuidadosa comparación de los riesgos y las cargas en relación con los beneficios previsibles que representan para las personas que participan en la investigación y para otras personas afectadas por el tema que se investiga; f) contar con el consentimiento previo, libre, escrito, informado y específico de la persona que participa en la investigación, a quien se le debe explicar, en términos comprensibles, los objetivos y la metodología de la investigación, sus riesgos y posibles beneficios; dicho consentimiento es revocable; g) no implicar para el participante riesgos y molestias desproporcionados en relación con los beneficios que se espera obtener de la investigación; h) resguardar la intimidad de la persona que participa en la investigación y la confidencialidad de su información personal; i) asegurar que la participación de los sujetos de la investigación no les resulte onerosa a éstos y que tengan acceso a la atención médica apropiada en caso de eventos adversos relacionados con la investigación, la que debe estar disponible cuando sea requerida; j) asegurar a los participantes de la investigación la disponibilidad y accesibilidad a los tratamientos que la investigación haya demostrado beneficiosos.", plainLanguageExplanation: "Establece el régimen de investigaciones en seres humanos. La investigación médica en seres humanos mediante intervenciones, tales como tratamientos, métodos de prevención, pruebas diagnósticas o predictivas, cuya eficacia o seguridad no están comprobadas científicamente, sólo puede ser realizada si se cumple con los siguientes requisito", practicalEffects: ['En la práctica, este artículo rige investigaciones en seres humanos. La investigación médica en seres humanos mediante intervenciones, tales como tratamientos, métodos de prevención, pruebas diagnósticas o predictivas,'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['investigaciones', 'seres', 'humanos', 'articulo 58'], segments: [], amendments: [] },
  { id: 'ccyc-art-59', lawId: 'codigo-civil-comercial', number: '59', order: 59, title: "Consentimiento informado para actos médicos e investigaciones en salud", originalText: "Consentimiento informado para actos médicos e investigaciones en salud. El consentimiento informado para actos médicos e investigaciones en salud es la declaración de voluntad expresada por el paciente, emitida luego de recibir información clara, precisa y adecuada, respecto a: a) su estado de salud; b) el procedimiento propuesto, con especificación de los objetivos perseguidos; c) los beneficios esperados del procedimiento; d) los riesgos, molestias y efectos adversos previsibles; e) la especificación de los procedimientos alternativos y sus riesgos, beneficios y perjuicios en relación con el procedimiento propuesto; f) las consecuencias previsibles de la no realización del procedimiento propuesto o de los alternativos especificados; g) en caso de padecer una enfermedad irreversible, incurable, o cuando se encuentre en estado terminal, o haya sufrido lesiones que lo coloquen en igual situación, el derecho a rechazar procedimientos quirúrgicos, de hidratación, alimentación, de reanimación artificial o al retiro de medidas de soporte vital, cuando sean extraordinarios o desproporcionados en relación a las perspectivas de mejoría, o produzcan sufrimiento desmesurado, o tengan por único efecto la prolongación en el tiempo de ese estadio terminal irreversible e incurable; h) el derecho a recibir cuidados paliativos integrales en el proceso de atención de su enfermedad o padecimiento. Ninguna persona con discapacidad puede ser sometida a investigaciones en salud sin su consentimiento libre e informado, para lo cual se le debe garantizar el acceso a los apoyos que necesite. Nadie puede ser sometido a exámenes o tratamientos clínicos o quirúrgicos sin su consentimiento libre e informado, excepto disposición legal en contrario. Si la persona se encuentra absolutamente imposibilitada para expresar su voluntad al tiempo de la atención médica y no la ha expresado anticipadamente, el consentimiento puede ser otorgado por el representante legal, el apoyo, el cónyuge, el conviviente, el pariente o el allegado que acompañe al paciente, siempre que medie situación de emergencia con riesgo cierto e inminente de un mal grave para su vida o su salud. En ausencia de todos ellos, el médico puede prescindir del consentimiento si su actuación es urgente y tiene por objeto evitar un mal grave al paciente.", currentText: "Consentimiento informado para actos médicos e investigaciones en salud. El consentimiento informado para actos médicos e investigaciones en salud es la declaración de voluntad expresada por el paciente, emitida luego de recibir información clara, precisa y adecuada, respecto a: a) su estado de salud; b) el procedimiento propuesto, con especificación de los objetivos perseguidos; c) los beneficios esperados del procedimiento; d) los riesgos, molestias y efectos adversos previsibles; e) la especificación de los procedimientos alternativos y sus riesgos, beneficios y perjuicios en relación con el procedimiento propuesto; f) las consecuencias previsibles de la no realización del procedimiento propuesto o de los alternativos especificados; g) en caso de padecer una enfermedad irreversible, incurable, o cuando se encuentre en estado terminal, o haya sufrido lesiones que lo coloquen en igual situación, el derecho a rechazar procedimientos quirúrgicos, de hidratación, alimentación, de reanimación artificial o al retiro de medidas de soporte vital, cuando sean extraordinarios o desproporcionados en relación a las perspectivas de mejoría, o produzcan sufrimiento desmesurado, o tengan por único efecto la prolongación en el tiempo de ese estadio terminal irreversible e incurable; h) el derecho a recibir cuidados paliativos integrales en el proceso de atención de su enfermedad o padecimiento. Ninguna persona con discapacidad puede ser sometida a investigaciones en salud sin su consentimiento libre e informado, para lo cual se le debe garantizar el acceso a los apoyos que necesite. Nadie puede ser sometido a exámenes o tratamientos clínicos o quirúrgicos sin su consentimiento libre e informado, excepto disposición legal en contrario. Si la persona se encuentra absolutamente imposibilitada para expresar su voluntad al tiempo de la atención médica y no la ha expresado anticipadamente, el consentimiento puede ser otorgado por el representante legal, el apoyo, el cónyuge, el conviviente, el pariente o el allegado que acompañe al paciente, siempre que medie situación de emergencia con riesgo cierto e inminente de un mal grave para su vida o su salud. En ausencia de todos ellos, el médico puede prescindir del consentimiento si su actuación es urgente y tiene por objeto evitar un mal grave al paciente.", plainLanguageExplanation: "Establece el régimen de consentimiento informado para actos médicos e investigaciones en salud. El consentimiento informado para actos médicos e investigaciones en salud es la declaración de voluntad expresada por el paciente, emitida luego de recibir información clara, precisa y adecuada, respecto a: a) su estado de salud; b) el procedimiento propuesto, con especificación", practicalEffects: ['En la práctica, este artículo rige consentimiento informado para actos médicos e investigaciones en salud. El consentimiento informado para actos médicos e investigaciones en salud es la declaración de voluntad expresada por el paciente, emitida luego de re'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['consentimiento', 'informado', 'para', 'actos', 'mdicos', 'investigaciones', 'salud', 'articulo 59'], segments: [], amendments: [] },
  { id: 'ccyc-art-60', lawId: 'codigo-civil-comercial', number: '60', order: 60, title: "Directivas médicas anticipadas", originalText: "Directivas médicas anticipadas. La persona plenamente capaz puede anticipar directivas y conferir mandato respecto de su salud y en previsión de su propia incapacidad. Puede también designar a la persona o personas que han de expresar el consentimiento para los actos médicos y para ejercer su curatela. Las directivas que impliquen desarrollar prácticas eutanásicas se tienen por no escritas. Esta declaración de voluntad puede ser libremente revocada en todo momento.", currentText: "Directivas médicas anticipadas. La persona plenamente capaz puede anticipar directivas y conferir mandato respecto de su salud y en previsión de su propia incapacidad. Puede también designar a la persona o personas que han de expresar el consentimiento para los actos médicos y para ejercer su curatela. Las directivas que impliquen desarrollar prácticas eutanásicas se tienen por no escritas. Esta declaración de voluntad puede ser libremente revocada en todo momento.", plainLanguageExplanation: "Establece el régimen de directivas médicas anticipadas. La persona plenamente capaz puede anticipar directivas y conferir mandato respecto de su salud y en previsión de su propia incapacidad.", practicalEffects: ['En la práctica, este artículo rige directivas médicas anticipadas. La persona plenamente capaz puede anticipar directivas y conferir mandato respecto de su salud y en previsión de su propia incapacidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['directivas', 'mdicas', 'anticipadas', 'articulo 60'], segments: [], amendments: [] },
  { id: 'ccyc-art-61', lawId: 'codigo-civil-comercial', number: '61', order: 61, title: "Exequias", originalText: "Exequias. La persona plenamente capaz puede disponer, por cualquier forma, el modo y circunstancias de sus exequias e inhumación, así como la dación de todo o parte del cadáver con fines terapéuticos, científicos, pedagógicos o de índole similar. Si la voluntad del fallecido no ha sido expresada, o ésta no es presumida, la decisión corresponde al cónyuge, al conviviente y en su defecto a los parientes según el orden sucesorio, quienes no pueden dar al cadáver un destino diferente al que habría dado el difunto de haber podido expresar su voluntad. CAPITULO 4 Nombre", currentText: "Exequias. La persona plenamente capaz puede disponer, por cualquier forma, el modo y circunstancias de sus exequias e inhumación, así como la dación de todo o parte del cadáver con fines terapéuticos, científicos, pedagógicos o de índole similar. Si la voluntad del fallecido no ha sido expresada, o ésta no es presumida, la decisión corresponde al cónyuge, al conviviente y en su defecto a los parientes según el orden sucesorio, quienes no pueden dar al cadáver un destino diferente al que habría dado el difunto de haber podido expresar su voluntad. CAPITULO 4 Nombre", plainLanguageExplanation: "Establece el régimen de exequias. La persona plenamente capaz puede disponer, por cualquier forma, el modo y circunstancias de sus exequias e inhumación, así como la dación de todo o parte del cadáver con fines terapéuticos, científicos, pedagógicos o de índole similar.", practicalEffects: ['En la práctica, este artículo rige exequias. La persona plenamente capaz puede disponer, por cualquier forma, el modo y circunstancias de sus exequias e inhumación, así como la dación de todo o p'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['exequiasarticulo 61'], segments: [], amendments: [] },
  { id: 'ccyc-art-62', lawId: 'codigo-civil-comercial', number: '62', order: 62, title: "Derecho y deber", originalText: "Derecho y deber. La persona humana tiene el derecho y el deber de usar el prenombre y el apellido que le corresponden.", currentText: "Derecho y deber. La persona humana tiene el derecho y el deber de usar el prenombre y el apellido que le corresponden.", plainLanguageExplanation: "Establece el régimen de derecho y deber. La persona humana tiene el derecho y el deber de usar el prenombre y el apellido que le corresponden.", practicalEffects: ['En la práctica, este artículo rige derecho y deber. La persona humana tiene el derecho y el deber de usar el prenombre y el apellido que le corresponden.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'deber', 'articulo 62'], segments: [], amendments: [] },
  { id: 'ccyc-art-63', lawId: 'codigo-civil-comercial', number: '63', order: 63, title: "Reglas concernientes al prenombre", originalText: "Reglas concernientes al prenombre. La elección del prenombre está sujeta a las reglas siguientes: a) corresponde a los padres o a las personas a quienes ellos den su autorización para tal fin; a falta o impedimento de uno de los padres, corresponde la elección o dar la autorización al otro; en defecto de todos, debe hacerse por los guardadores, el Ministerio Público o el funcionario del Registro del Estado Civil y Capacidad de las Personas; b) no pueden inscribirse más de tres prenombres, apellidos como prenombres, primeros prenombres idénticos a primeros prenombres de hermanos vivos; tampoco pueden inscribirse prenombres extravagantes; c) pueden inscribirse nombres aborígenes o derivados de voces aborígenes autóctonas y latinoamericanas.", currentText: "Reglas concernientes al prenombre. La elección del prenombre está sujeta a las reglas siguientes: a) corresponde a los padres o a las personas a quienes ellos den su autorización para tal fin; a falta o impedimento de uno de los padres, corresponde la elección o dar la autorización al otro; en defecto de todos, debe hacerse por los guardadores, el Ministerio Público o el funcionario del Registro del Estado Civil y Capacidad de las Personas; b) no pueden inscribirse más de tres prenombres, apellidos como prenombres, primeros prenombres idénticos a primeros prenombres de hermanos vivos; tampoco pueden inscribirse prenombres extravagantes; c) pueden inscribirse nombres aborígenes o derivados de voces aborígenes autóctonas y latinoamericanas.", plainLanguageExplanation: "Establece el régimen de reglas concernientes al prenombre. La elección del prenombre está sujeta a las reglas siguientes: a) corresponde a los padres o a las personas a quienes ellos den su autorización para tal fin; a falta o impedimento de uno de los padres, corresponde la elección o dar la autorización al otro; en defecto de todos, de", practicalEffects: ['En la práctica, este artículo rige reglas concernientes al prenombre. La elección del prenombre está sujeta a las reglas siguientes: a) corresponde a los padres o a las personas a quienes ellos den su autorización para t'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglas', 'concernientes', 'prenombre', 'articulo 63'], segments: [], amendments: [] },
  { id: 'ccyc-art-64', lawId: 'codigo-civil-comercial', number: '64', order: 64, title: "Apellido de los hijos", originalText: "Apellido de los hijos. El hijo matrimonial lleva el primer apellido de alguno de los cónyuges; en caso de no haber acuerdo, se determina por sorteo realizado en el Registro del Estado Civil y Capacidad de las Personas. A pedido de los padres, o del interesado con edad y madurez suficiente, se puede agregar el apellido del otro. Todos los hijos de un mismo matrimonio deben llevar el apellido y la integración compuesta que se haya decidido para el primero de los hijos. El hijo extramatrimonial con un solo vínculo filial lleva el apellido de ese progenitor. Si la filiación de ambos padres se determina simultáneamente, se aplica el primer párrafo de este artículo. Si la segunda filiación se determina después, los padres acuerdan el orden; a falta de acuerdo, el juez dispone el orden de los apellidos, según el interés superior del niño.", currentText: "Apellido de los hijos. El hijo matrimonial lleva el primer apellido de alguno de los cónyuges; en caso de no haber acuerdo, se determina por sorteo realizado en el Registro del Estado Civil y Capacidad de las Personas. A pedido de los padres, o del interesado con edad y madurez suficiente, se puede agregar el apellido del otro. Todos los hijos de un mismo matrimonio deben llevar el apellido y la integración compuesta que se haya decidido para el primero de los hijos. El hijo extramatrimonial con un solo vínculo filial lleva el apellido de ese progenitor. Si la filiación de ambos padres se determina simultáneamente, se aplica el primer párrafo de este artículo. Si la segunda filiación se determina después, los padres acuerdan el orden; a falta de acuerdo, el juez dispone el orden de los apellidos, según el interés superior del niño.", plainLanguageExplanation: "Establece el régimen de apellido de los hijos. El hijo matrimonial lleva el primer apellido de alguno de los cónyuges; en caso de no haber acuerdo, se determina por sorteo realizado en el Registro del Estado Civil y Capacidad de las Personas.", practicalEffects: ['En la práctica, este artículo rige apellido de los hijos. El hijo matrimonial lleva el primer apellido de alguno de los cónyuges; en caso de no haber acuerdo, se determina por sorteo realizado en el Registro del Estado Civil y Capacidad de las Personas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['apellido', 'hijos', 'articulo 64'], segments: [], amendments: [] },
  { id: 'ccyc-art-65', lawId: 'codigo-civil-comercial', number: '65', order: 65, title: "Apellido de persona menor de edad sin filiación determinada", originalText: "Apellido de persona menor de edad sin filiación determinada. La persona menor de edad sin filiación determinada debe ser anotada por el oficial del Registro del Estado Civil y Capacidad de las Personas con el apellido que está usando, o en su defecto, con un apellido común.", currentText: "Apellido de persona menor de edad sin filiación determinada. La persona menor de edad sin filiación determinada debe ser anotada por el oficial del Registro del Estado Civil y Capacidad de las Personas con el apellido que está usando, o en su defecto, con un apellido común.", plainLanguageExplanation: "Establece el régimen de apellido de persona menor de edad sin filiación determinada. La persona menor de edad sin filiación determinada debe ser anotada por el oficial del Registro del Estado Civil y Capacidad de las Personas con el apellido que está usando, o en su defecto, con un apellido común.", practicalEffects: ['En la práctica, este artículo rige apellido de persona menor de edad sin filiación determinada. La persona menor de edad sin filiación determinada debe ser anotada por el oficial del Registro del Estado Civil y Capacidad de las Personas con el ap'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['apellido', 'persona', 'menor', 'edad', 'filiacin', 'determinada', 'articulo 65'], segments: [], amendments: [] },
  { id: 'ccyc-art-66', lawId: 'codigo-civil-comercial', number: '66', order: 66, title: "Casos especiales", originalText: "Casos especiales. La persona con edad y grado de madurez suficiente que carezca de apellido inscripto puede pedir la inscripción del que está usando.", currentText: "Casos especiales. La persona con edad y grado de madurez suficiente que carezca de apellido inscripto puede pedir la inscripción del que está usando.", plainLanguageExplanation: "Establece el régimen de casos especiales. La persona con edad y grado de madurez suficiente que carezca de apellido inscripto puede pedir la inscripción del que está usando.", practicalEffects: ['En la práctica, este artículo rige casos especiales. La persona con edad y grado de madurez suficiente que carezca de apellido inscripto puede pedir la inscripción del que está usando.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casos', 'especiales', 'articulo 66'], segments: [], amendments: [] },
  { id: 'ccyc-art-67', lawId: 'codigo-civil-comercial', number: '67', order: 67, title: "Cónyuges", originalText: "Cónyuges. Cualquiera de los cónyuges puede optar por usar el apellido del otro, con la preposición 'de' o sin ella. La persona divorciada o cuyo matrimonio ha sido declarado nulo no puede usar el apellido del otro cónyuge, excepto que, por motivos razonables, el juez la autorice a conservarlo. El cónyuge viudo puede seguir usando el apellido del otro cónyuge mientras no contraiga nuevas nupcias, ni constituya unión convivencial.", currentText: "Cónyuges. Cualquiera de los cónyuges puede optar por usar el apellido del otro, con la preposición 'de' o sin ella. La persona divorciada o cuyo matrimonio ha sido declarado nulo no puede usar el apellido del otro cónyuge, excepto que, por motivos razonables, el juez la autorice a conservarlo. El cónyuge viudo puede seguir usando el apellido del otro cónyuge mientras no contraiga nuevas nupcias, ni constituya unión convivencial.", plainLanguageExplanation: "Establece el régimen de cónyuges. Cualquiera de los cónyuges puede optar por usar el apellido del otro, con la preposición 'de' o sin ella.", practicalEffects: ['En la práctica, este artículo rige cónyuges. Cualquiera de los cónyuges puede optar por usar el apellido del otro, con la preposición \'de\' o sin ella.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cnyugesarticulo 67'], segments: [], amendments: [] },
  { id: 'ccyc-art-68', lawId: 'codigo-civil-comercial', number: '68', order: 68, title: "Nombre del hijo adoptivo", originalText: "Nombre del hijo adoptivo. El nombre del hijo adoptivo se rige por lo dispuesto en el Capítulo 5, Título VI del Libro Segundo de este Código.", currentText: "Nombre del hijo adoptivo. El nombre del hijo adoptivo se rige por lo dispuesto en el Capítulo 5, Título VI del Libro Segundo de este Código.", plainLanguageExplanation: "Establece el régimen de nombre del hijo adoptivo. El nombre del hijo adoptivo se rige por lo dispuesto en el Capítulo 5, Título VI del Libro Segundo de este Código.", practicalEffects: ['En la práctica, este artículo rige nombre del hijo adoptivo. El nombre del hijo adoptivo se rige por lo dispuesto en el Capítulo 5, Título VI del Libro Segundo de este Código.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['nombre', 'hijo', 'adoptivo', 'articulo 68'], segments: [], amendments: [] },
  { id: 'ccyc-art-69', lawId: 'codigo-civil-comercial', number: '69', order: 69, title: "Cambio de nombre", originalText: "Cambio de nombre. El cambio de prenombre o apellido sólo procede si existen justos motivos a criterio del juez. Se considera justo motivo, de acuerdo a las particularidades del caso, entre otros, a: a) el seudónimo, cuando hubiese adquirido notoriedad; b) la raigambre cultural, étnica o religiosa; c) la afectación de la personalidad de la persona interesada, cualquiera sea su causa, siempre que se encuentre acreditada. Se consideran justos motivos, y no requieren intervención judicial, el cambio de prenombre por razón de identidad de género y el cambio de prenombre y apellido por haber sido víctima de desaparición forzada, apropiación ilegal o alteración o supresión del estado civil o de la identidad.", currentText: "Cambio de nombre. El cambio de prenombre o apellido sólo procede si existen justos motivos a criterio del juez. Se considera justo motivo, de acuerdo a las particularidades del caso, entre otros, a: a) el seudónimo, cuando hubiese adquirido notoriedad; b) la raigambre cultural, étnica o religiosa; c) la afectación de la personalidad de la persona interesada, cualquiera sea su causa, siempre que se encuentre acreditada. Se consideran justos motivos, y no requieren intervención judicial, el cambio de prenombre por razón de identidad de género y el cambio de prenombre y apellido por haber sido víctima de desaparición forzada, apropiación ilegal o alteración o supresión del estado civil o de la identidad.", plainLanguageExplanation: "Establece el régimen de cambio de nombre. El cambio de prenombre o apellido sólo procede si existen justos motivos a criterio del juez.", practicalEffects: ['En la práctica, este artículo rige cambio de nombre. El cambio de prenombre o apellido sólo procede si existen justos motivos a criterio del juez.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cambio', 'nombre', 'articulo 69'], segments: [], amendments: [] },
  { id: 'ccyc-art-70', lawId: 'codigo-civil-comercial', number: '70', order: 70, title: "Proceso", originalText: "Proceso. Todos los cambios de prenombre o apellido deben tramitar por el proceso más abreviado que prevea la ley local, con intervención del Ministerio Público. El pedido debe publicarse en el diario oficial una vez por mes, en el lapso de dos meses. Puede formularse oposición dentro de los quince días hábiles contados desde la última publicación. Debe requerirse información sobre medidas precautorias existentes respecto del interesado. La sentencia es oponible a terceros desde su inscripción en el Registro del Estado Civil y Capacidad de las Personas. Deben rectificarse todas las partidas, títulos y asientos registrales que sean necesarios.", currentText: "Proceso. Todos los cambios de prenombre o apellido deben tramitar por el proceso más abreviado que prevea la ley local, con intervención del Ministerio Público. El pedido debe publicarse en el diario oficial una vez por mes, en el lapso de dos meses. Puede formularse oposición dentro de los quince días hábiles contados desde la última publicación. Debe requerirse información sobre medidas precautorias existentes respecto del interesado. La sentencia es oponible a terceros desde su inscripción en el Registro del Estado Civil y Capacidad de las Personas. Deben rectificarse todas las partidas, títulos y asientos registrales que sean necesarios.", plainLanguageExplanation: "Establece el régimen de proceso. Todos los cambios de prenombre o apellido deben tramitar por el proceso más abreviado que prevea la ley local, con intervención del Ministerio Público.", practicalEffects: ['En la práctica, este artículo rige proceso. Todos los cambios de prenombre o apellido deben tramitar por el proceso más abreviado que prevea la ley local, con intervención del Ministerio Público.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['procesoarticulo 70'], segments: [], amendments: [] },
  { id: 'ccyc-art-71', lawId: 'codigo-civil-comercial', number: '71', order: 71, title: "Acciones de protección del nombre", originalText: "Acciones de protección del nombre. Puede ejercer acciones en defensa de su nombre: a) aquel a quien le es desconocido el uso de su nombre, para que le sea reconocido y se prohíba toda futura impugnación por quien lo niega; se debe ordenar la publicación de la sentencia a costa del demandado; b) aquel cuyo nombre es indebidamente usado por otro, para que cese en ese uso; c) aquel cuyo nombre es usado para la designación de cosas o personajes de fantasía, si ello le causa perjuicio material o moral, para que cese el uso. En todos los casos puede demandarse la reparación de los daños y el juez puede disponer la publicación de la sentencia. Las acciones pueden ser ejercidas exclusivamente por el interesado; si ha fallecido, por sus descendientes, cónyuge o conviviente, y a falta de éstos, por los ascendientes o hermanos.", currentText: "Acciones de protección del nombre. Puede ejercer acciones en defensa de su nombre: a) aquel a quien le es desconocido el uso de su nombre, para que le sea reconocido y se prohíba toda futura impugnación por quien lo niega; se debe ordenar la publicación de la sentencia a costa del demandado; b) aquel cuyo nombre es indebidamente usado por otro, para que cese en ese uso; c) aquel cuyo nombre es usado para la designación de cosas o personajes de fantasía, si ello le causa perjuicio material o moral, para que cese el uso. En todos los casos puede demandarse la reparación de los daños y el juez puede disponer la publicación de la sentencia. Las acciones pueden ser ejercidas exclusivamente por el interesado; si ha fallecido, por sus descendientes, cónyuge o conviviente, y a falta de éstos, por los ascendientes o hermanos.", plainLanguageExplanation: "Establece el régimen de acciones de protección del nombre. Puede ejercer acciones en defensa de su nombre: a) aquel a quien le es desconocido el uso de su nombre, para que le sea reconocido y se prohíba toda futura impugnación por quien lo niega; se debe ordenar la publicación de la sentencia a costa del demandado; b) aquel cuyo nombre e", practicalEffects: ['En la práctica, este artículo rige acciones de protección del nombre. Puede ejercer acciones en defensa de su nombre: a) aquel a quien le es desconocido el uso de su nombre, para que le sea reconocido y se prohíba toda f'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['acciones', 'proteccin', 'nombre', 'articulo 71'], segments: [], amendments: [] },
  { id: 'ccyc-art-72', lawId: 'codigo-civil-comercial', number: '72', order: 72, title: "Seudónimo", originalText: "Seudónimo. El seudónimo notorio goza de la tutela del nombre. CAPITULO 5 Domicilio", currentText: "Seudónimo. El seudónimo notorio goza de la tutela del nombre. CAPITULO 5 Domicilio", plainLanguageExplanation: "Establece el régimen de seudónimo. El seudónimo notorio goza de la tutela del nombre.", practicalEffects: ['En la práctica, este artículo rige seudónimo. El seudónimo notorio goza de la tutela del nombre.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['seudnimoarticulo 72'], segments: [], amendments: [] },
  { id: 'ccyc-art-73', lawId: 'codigo-civil-comercial', number: '73', order: 73, title: "Domicilio real", originalText: "Domicilio real. La persona humana tiene domicilio real en el lugar de su residencia habitual. Si ejerce actividad profesional o económica lo tiene en el lugar donde la desempeña para el cumplimiento de las obligaciones emergentes de dicha actividad.", currentText: "Domicilio real. La persona humana tiene domicilio real en el lugar de su residencia habitual. Si ejerce actividad profesional o económica lo tiene en el lugar donde la desempeña para el cumplimiento de las obligaciones emergentes de dicha actividad.", plainLanguageExplanation: "Establece el régimen de domicilio real. La persona humana tiene domicilio real en el lugar de su residencia habitual.", practicalEffects: ['En la práctica, este artículo rige domicilio real. La persona humana tiene domicilio real en el lugar de su residencia habitual.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['domicilio', 'real', 'articulo 73'], segments: [], amendments: [] },
  { id: 'ccyc-art-74', lawId: 'codigo-civil-comercial', number: '74', order: 74, title: "Domicilio legal", originalText: "Domicilio legal. El domicilio legal es el lugar donde la ley presume, sin admitir prueba en contra, que una persona reside de manera permanente para el ejercicio de sus derechos y el cumplimiento de sus obligaciones. Sólo la ley puede establecerlo, y sin perjuicio de lo dispuesto en normas especiales: a) los funcionarios públicos, tienen su domicilio en el lugar en que deben cumplir sus funciones, no siendo éstas temporarias, periódicas, o de simple comisión; b) los militares en servicio activo tienen su domicilio en el lugar en que lo están prestando; c) los transeúntes o las personas de ejercicio ambulante, como los que no tienen domicilio conocido, lo tienen en el lugar de su residencia actual; d) las personas incapaces lo tienen en el domicilio de sus representantes.", currentText: "Domicilio legal. El domicilio legal es el lugar donde la ley presume, sin admitir prueba en contra, que una persona reside de manera permanente para el ejercicio de sus derechos y el cumplimiento de sus obligaciones. Sólo la ley puede establecerlo, y sin perjuicio de lo dispuesto en normas especiales: a) los funcionarios públicos, tienen su domicilio en el lugar en que deben cumplir sus funciones, no siendo éstas temporarias, periódicas, o de simple comisión; b) los militares en servicio activo tienen su domicilio en el lugar en que lo están prestando; c) los transeúntes o las personas de ejercicio ambulante, como los que no tienen domicilio conocido, lo tienen en el lugar de su residencia actual; d) las personas incapaces lo tienen en el domicilio de sus representantes.", plainLanguageExplanation: "Establece el régimen de domicilio legal. El domicilio legal es el lugar donde la ley presume, sin admitir prueba en contra, que una persona reside de manera permanente para el ejercicio de sus derechos y el cumplimiento de sus obligaciones.", practicalEffects: ['En la práctica, este artículo rige domicilio legal. El domicilio legal es el lugar donde la ley presume, sin admitir prueba en contra, que una persona reside de manera permanente para el ejercicio de sus derechos y el cumplimiento de sus obligaciones.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['domicilio', 'legal', 'articulo 74'], segments: [], amendments: [] },
  { id: 'ccyc-art-75', lawId: 'codigo-civil-comercial', number: '75', order: 75, title: "Domicilio especial", originalText: "Domicilio especial. Las partes de un contrato pueden elegir un domicilio para el ejercicio de los derechos y obligaciones que de él emanan. Pueden, además, constituir un domicilio electrónico en el que se tengan por eficaces todas las notificaciones, comunicaciones y emplazamientos que allí se dirijan. (Artículo sustituido por art. 11 del Decreto N° 338/2025 B.O. 20/05/2025. Vigencia: a partir del día de su publicación en el BOLETÍN OFICIAL)", currentText: "Domicilio especial. Las partes de un contrato pueden elegir un domicilio para el ejercicio de los derechos y obligaciones que de él emanan. Pueden, además, constituir un domicilio electrónico en el que se tengan por eficaces todas las notificaciones, comunicaciones y emplazamientos que allí se dirijan. (Artículo sustituido por art. 11 del Decreto N° 338/2025 B.O. 20/05/2025. Vigencia: a partir del día de su publicación en el BOLETÍN OFICIAL)", plainLanguageExplanation: "Establece el régimen de domicilio especial. Las partes de un contrato pueden elegir un domicilio para el ejercicio de los derechos y obligaciones que de él emanan.", practicalEffects: ['En la práctica, este artículo rige domicilio especial. Las partes de un contrato pueden elegir un domicilio para el ejercicio de los derechos y obligaciones que de él emanan.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['domicilio', 'especial', 'articulo 75'], segments: [], amendments: [] },
  { id: 'ccyc-art-76', lawId: 'codigo-civil-comercial', number: '76', order: 76, title: "Domicilio ignorado", originalText: "Domicilio ignorado. La persona cuyo domicilio no es conocido lo tiene en el lugar donde se encuentra; y si éste también se ignora en el último domicilio conocido.", currentText: "Domicilio ignorado. La persona cuyo domicilio no es conocido lo tiene en el lugar donde se encuentra; y si éste también se ignora en el último domicilio conocido.", plainLanguageExplanation: "Establece el régimen de domicilio ignorado. La persona cuyo domicilio no es conocido lo tiene en el lugar donde se encuentra; y si éste también se ignora en el último domicilio conocido.", practicalEffects: ['En la práctica, este artículo rige domicilio ignorado. La persona cuyo domicilio no es conocido lo tiene en el lugar donde se encuentra; y si éste también se ignora en el último domicilio conocido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['domicilio', 'ignorado', 'articulo 76'], segments: [], amendments: [] },
  { id: 'ccyc-art-77', lawId: 'codigo-civil-comercial', number: '77', order: 77, title: "Cambio de domicilio", originalText: "Cambio de domicilio. El domicilio puede cambiarse de un lugar a otro. Esta facultad no puede ser coartada por contrato, ni por disposición de última voluntad. El cambio de domicilio se verifica instantáneamente por el hecho de trasladar la residencia de un lugar a otro con ánimo de permanecer en ella.", currentText: "Cambio de domicilio. El domicilio puede cambiarse de un lugar a otro. Esta facultad no puede ser coartada por contrato, ni por disposición de última voluntad. El cambio de domicilio se verifica instantáneamente por el hecho de trasladar la residencia de un lugar a otro con ánimo de permanecer en ella.", plainLanguageExplanation: "Establece el régimen de cambio de domicilio. El domicilio puede cambiarse de un lugar a otro.", practicalEffects: ['En la práctica, este artículo rige cambio de domicilio. El domicilio puede cambiarse de un lugar a otro.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cambio', 'domicilio', 'articulo 77'], segments: [], amendments: [] },
  { id: 'ccyc-art-78', lawId: 'codigo-civil-comercial', number: '78', order: 78, title: "Efecto", originalText: "Efecto. El domicilio determina la competencia de las autoridades en las relaciones jurídicas. La elección de un domicilio produce la prórroga de la competencia. CAPITULO 6 Ausencia", currentText: "Efecto. El domicilio determina la competencia de las autoridades en las relaciones jurídicas. La elección de un domicilio produce la prórroga de la competencia. CAPITULO 6 Ausencia", plainLanguageExplanation: "Establece el régimen de efecto. El domicilio determina la competencia de las autoridades en las relaciones jurídicas.", practicalEffects: ['En la práctica, este artículo rige efecto. El domicilio determina la competencia de las autoridades en las relaciones jurídicas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectoarticulo 78'], segments: [], amendments: [] },
  { id: 'ccyc-art-79', lawId: 'codigo-civil-comercial', number: '79', order: 79, title: "Ausencia simple", originalText: "Ausencia simple. Si una persona ha desaparecido de su domicilio, sin tenerse noticias de ella, y sin haber dejado apoderado, puede designarse un curador a sus bienes si el cuidado de éstos lo exige. La misma regla se debe aplicar si existe apoderado, pero sus poderes son insuficientes o no desempeña convenientemente el mandato.", currentText: "Ausencia simple. Si una persona ha desaparecido de su domicilio, sin tenerse noticias de ella, y sin haber dejado apoderado, puede designarse un curador a sus bienes si el cuidado de éstos lo exige. La misma regla se debe aplicar si existe apoderado, pero sus poderes son insuficientes o no desempeña convenientemente el mandato.", plainLanguageExplanation: "Establece el régimen de ausencia simple. Si una persona ha desaparecido de su domicilio, sin tenerse noticias de ella, y sin haber dejado apoderado, puede designarse un curador a sus bienes si el cuidado de éstos lo exige.", practicalEffects: ['En la práctica, este artículo rige ausencia simple. Si una persona ha desaparecido de su domicilio, sin tenerse noticias de ella, y sin haber dejado apoderado, puede designarse un curador a sus bienes si el cuidado de éstos lo exige.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ausencia', 'simple', 'articulo 79'], segments: [], amendments: [] },
  { id: 'ccyc-art-80', lawId: 'codigo-civil-comercial', number: '80', order: 80, title: "Legitimados", originalText: "Legitimados. Pueden pedir la declaración de ausencia, el Ministerio Público y toda persona que tenga interés legítimo respecto de los bienes del ausente.", currentText: "Legitimados. Pueden pedir la declaración de ausencia, el Ministerio Público y toda persona que tenga interés legítimo respecto de los bienes del ausente.", plainLanguageExplanation: "Establece el régimen de legitimados. Pueden pedir la declaración de ausencia, el Ministerio Público y toda persona que tenga interés legítimo respecto de los bienes del ausente.", practicalEffects: ['En la práctica, este artículo rige legitimados. Pueden pedir la declaración de ausencia, el Ministerio Público y toda persona que tenga interés legítimo respecto de los bienes del ausente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legitimadosarticulo 80'], segments: [], amendments: [] },
  { id: 'ccyc-art-81', lawId: 'codigo-civil-comercial', number: '81', order: 81, title: "Juez competente", originalText: "Juez competente. Es competente el juez del domicilio del ausente. Si éste no lo tuvo en el país, o no es conocido, es competente el juez del lugar en donde existan bienes cuyo cuidado es necesario; si existen bienes en distintas jurisdicciones, el que haya prevenido.", currentText: "Juez competente. Es competente el juez del domicilio del ausente. Si éste no lo tuvo en el país, o no es conocido, es competente el juez del lugar en donde existan bienes cuyo cuidado es necesario; si existen bienes en distintas jurisdicciones, el que haya prevenido.", plainLanguageExplanation: "Establece el régimen de juez competente. Es competente el juez del domicilio del ausente.", practicalEffects: ['En la práctica, este artículo rige juez competente. Es competente el juez del domicilio del ausente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['juez', 'competente', 'articulo 81'], segments: [], amendments: [] },
  { id: 'ccyc-art-82', lawId: 'codigo-civil-comercial', number: '82', order: 82, title: "Procedimiento", originalText: "Procedimiento. El presunto ausente debe ser citado por edictos durante cinco días, y si vencido el plazo no comparece, se debe dar intervención al defensor oficial o en su defecto, nombrarse defensor al ausente. El Ministerio Público es parte necesaria en el juicio. Si antes de la declaración de ausencia se promueven acciones contra el ausente, debe representarlo el defensor. En caso de urgencia, el juez puede designar un administrador provisional o adoptar las medidas que las circunstancias aconsejan.", currentText: "Procedimiento. El presunto ausente debe ser citado por edictos durante cinco días, y si vencido el plazo no comparece, se debe dar intervención al defensor oficial o en su defecto, nombrarse defensor al ausente. El Ministerio Público es parte necesaria en el juicio. Si antes de la declaración de ausencia se promueven acciones contra el ausente, debe representarlo el defensor. En caso de urgencia, el juez puede designar un administrador provisional o adoptar las medidas que las circunstancias aconsejan.", plainLanguageExplanation: "Establece el régimen de procedimiento. El presunto ausente debe ser citado por edictos durante cinco días, y si vencido el plazo no comparece, se debe dar intervención al defensor oficial o en su defecto, nombrarse defensor al ausente.", practicalEffects: ['En la práctica, este artículo rige procedimiento. El presunto ausente debe ser citado por edictos durante cinco días, y si vencido el plazo no comparece, se debe dar intervención al defensor oficial o en su defecto, nombrarse defensor al ausente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['procedimientoarticulo 82'], segments: [], amendments: [] },
  { id: 'ccyc-art-83', lawId: 'codigo-civil-comercial', number: '83', order: 83, title: "Sentencia", originalText: "Sentencia. Oído el defensor, si concurren los extremos legales, se debe declarar la ausencia y nombrar curador. Para la designación se debe estar a lo previsto para el discernimiento de curatela. El curador sólo puede realizar los actos de conservación y administración ordinaria de los bienes. Todo acto que exceda la administración ordinaria debe ser autorizado por el juez; la autorización debe ser otorgada sólo en caso de necesidad evidente e impostergable. Los frutos de los bienes administrados deben ser utilizados para el sostenimiento de los descendientes, cónyuge, conviviente y ascendientes del ausente.", currentText: "Sentencia. Oído el defensor, si concurren los extremos legales, se debe declarar la ausencia y nombrar curador. Para la designación se debe estar a lo previsto para el discernimiento de curatela. El curador sólo puede realizar los actos de conservación y administración ordinaria de los bienes. Todo acto que exceda la administración ordinaria debe ser autorizado por el juez; la autorización debe ser otorgada sólo en caso de necesidad evidente e impostergable. Los frutos de los bienes administrados deben ser utilizados para el sostenimiento de los descendientes, cónyuge, conviviente y ascendientes del ausente.", plainLanguageExplanation: "Establece el régimen de sentencia. Oído el defensor, si concurren los extremos legales, se debe declarar la ausencia y nombrar curador.", practicalEffects: ['En la práctica, este artículo rige sentencia. Oído el defensor, si concurren los extremos legales, se debe declarar la ausencia y nombrar curador.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sentenciaarticulo 83'], segments: [], amendments: [] },
  { id: 'ccyc-art-84', lawId: 'codigo-civil-comercial', number: '84', order: 84, title: "Conclusión de la curatela", originalText: "Conclusión de la curatela. Termina la curatela del ausente por: a) la presentación del ausente, personalmente o por apoderado; b) su muerte; c) su fallecimiento presunto judicialmente declarado. CAPITULO 7 Presunción de fallecimiento", currentText: "Conclusión de la curatela. Termina la curatela del ausente por: a) la presentación del ausente, personalmente o por apoderado; b) su muerte; c) su fallecimiento presunto judicialmente declarado. CAPITULO 7 Presunción de fallecimiento", plainLanguageExplanation: "Establece el régimen de conclusión de la curatela. Termina la curatela del ausente por: a) la presentación del ausente, personalmente o por apoderado; b) su muerte; c) su fallecimiento presunto judicialmente declarado.", practicalEffects: ['En la práctica, este artículo rige conclusión de la curatela. Termina la curatela del ausente por: a) la presentación del ausente, personalmente o por apoderado; b) su muerte; c) su fallecimiento presunto judicialmente declarado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conclusin', 'curatela', 'articulo 84'], segments: [], amendments: [] },
  { id: 'ccyc-art-85', lawId: 'codigo-civil-comercial', number: '85', order: 85, title: "Caso ordinario", originalText: "Caso ordinario. La ausencia de una persona de su domicilio sin que se tenga noticia de ella por el término de tres años, causa la presunción de su fallecimiento aunque haya dejado apoderado. El plazo debe contarse desde la fecha de la última noticia del ausente.", currentText: "Caso ordinario. La ausencia de una persona de su domicilio sin que se tenga noticia de ella por el término de tres años, causa la presunción de su fallecimiento aunque haya dejado apoderado. El plazo debe contarse desde la fecha de la última noticia del ausente.", plainLanguageExplanation: "Establece el régimen de caso ordinario. La ausencia de una persona de su domicilio sin que se tenga noticia de ella por el término de tres años, causa la presunción de su fallecimiento aunque haya dejado apoderado.", practicalEffects: ['En la práctica, este artículo rige caso ordinario. La ausencia de una persona de su domicilio sin que se tenga noticia de ella por el término de tres años, causa la presunción de su fallecimiento aunque haya dejado apoderado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caso', 'ordinario', 'articulo 85'], segments: [], amendments: [] },
  { id: 'ccyc-art-86', lawId: 'codigo-civil-comercial', number: '86', order: 86, title: "Casos extraordinarios", originalText: "Casos extraordinarios. Se presume también el fallecimiento de un ausente: a) si por última vez se encontró en el lugar de un incendio, terremoto, acción de guerra u otro suceso semejante, susceptible de ocasionar la muerte, o participó de una actividad que implique el mismo riesgo, y no se tiene noticia de él por el término de dos años, contados desde el día en que el suceso ocurrió o pudo haber ocurrido; b) si encontrándose en un buque o aeronave naufragados o perdidos, no se tuviese noticia de su existencia por el término de seis meses desde el día en que el suceso ocurrió o pudo haber ocurrido.", currentText: "Casos extraordinarios. Se presume también el fallecimiento de un ausente: a) si por última vez se encontró en el lugar de un incendio, terremoto, acción de guerra u otro suceso semejante, susceptible de ocasionar la muerte, o participó de una actividad que implique el mismo riesgo, y no se tiene noticia de él por el término de dos años, contados desde el día en que el suceso ocurrió o pudo haber ocurrido; b) si encontrándose en un buque o aeronave naufragados o perdidos, no se tuviese noticia de su existencia por el término de seis meses desde el día en que el suceso ocurrió o pudo haber ocurrido.", plainLanguageExplanation: "Establece el régimen de casos extraordinarios. Se presume también el fallecimiento de un ausente: a) si por última vez se encontró en el lugar de un incendio, terremoto, acción de guerra u otro suceso semejante, susceptible de ocasionar la muerte, o participó de una actividad que implique el mismo riesgo, y no se tiene notici", practicalEffects: ['En la práctica, este artículo rige casos extraordinarios. Se presume también el fallecimiento de un ausente: a) si por última vez se encontró en el lugar de un incendio, terremoto, acción de guerra u otro suc'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casos', 'extraordinarios', 'articulo 86'], segments: [], amendments: [] },
  { id: 'ccyc-art-87', lawId: 'codigo-civil-comercial', number: '87', order: 87, title: "Legitimados", originalText: "Legitimados. Cualquiera que tenga algún derecho subordinado a la muerte de la persona de que se trate, puede pedir la declaración de fallecimiento presunto, justificando los extremos legales y la realización de diligencias tendientes a la averiguación de la existencia del ausente. Es competente el juez del domicilio del ausente.", currentText: "Legitimados. Cualquiera que tenga algún derecho subordinado a la muerte de la persona de que se trate, puede pedir la declaración de fallecimiento presunto, justificando los extremos legales y la realización de diligencias tendientes a la averiguación de la existencia del ausente. Es competente el juez del domicilio del ausente.", plainLanguageExplanation: "Establece el régimen de legitimados. Cualquiera que tenga algún derecho subordinado a la muerte de la persona de que se trate, puede pedir la declaración de fallecimiento presunto, justificando los extremos legales y la realización de diligencias tendientes a la averiguación de la existencia del ausente.", practicalEffects: ['En la práctica, este artículo rige legitimados. Cualquiera que tenga algún derecho subordinado a la muerte de la persona de que se trate, puede pedir la declaración de fallecimiento presunto, justif'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legitimadosarticulo 87'], segments: [], amendments: [] },
  { id: 'ccyc-art-88', lawId: 'codigo-civil-comercial', number: '88', order: 88, title: "Procedimiento", originalText: "Procedimiento. Curador a los bienes. El juez debe nombrar defensor al ausente o dar intervención al defensor oficial, y citar a aquél por edictos una vez por mes durante seis meses. También debe designar un curador a sus bienes, si no hay mandatario con poderes suficientes, o si por cualquier causa aquél no desempeña correctamente el mandato. La declaración de simple ausencia no constituye presupuesto necesario para la declaración de fallecimiento presunto, ni suple la comprobación de las diligencias realizadas para conocer la existencia del ausente.", currentText: "Procedimiento. Curador a los bienes. El juez debe nombrar defensor al ausente o dar intervención al defensor oficial, y citar a aquél por edictos una vez por mes durante seis meses. También debe designar un curador a sus bienes, si no hay mandatario con poderes suficientes, o si por cualquier causa aquél no desempeña correctamente el mandato. La declaración de simple ausencia no constituye presupuesto necesario para la declaración de fallecimiento presunto, ni suple la comprobación de las diligencias realizadas para conocer la existencia del ausente.", plainLanguageExplanation: "Establece el régimen de procedimiento. Curador a los bienes.", practicalEffects: ['En la práctica, este artículo rige procedimiento. Curador a los bienes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['procedimientoarticulo 88'], segments: [], amendments: [] },
  { id: 'ccyc-art-89', lawId: 'codigo-civil-comercial', number: '89', order: 89, title: "Declaración del fallecimiento presunto", originalText: "Declaración del fallecimiento presunto. Pasados los seis meses, recibida la prueba y oído el defensor, el juez debe declarar el fallecimiento presunto si están acreditados los extremos legales, fijar el día presuntivo del fallecimiento y disponer la inscripción de la sentencia.", currentText: "Declaración del fallecimiento presunto. Pasados los seis meses, recibida la prueba y oído el defensor, el juez debe declarar el fallecimiento presunto si están acreditados los extremos legales, fijar el día presuntivo del fallecimiento y disponer la inscripción de la sentencia.", plainLanguageExplanation: "Establece el régimen de declaración del fallecimiento presunto. Pasados los seis meses, recibida la prueba y oído el defensor, el juez debe declarar el fallecimiento presunto si están acreditados los extremos legales, fijar el día presuntivo del fallecimiento y disponer la inscripción de la sentencia.", practicalEffects: ['En la práctica, este artículo rige declaración del fallecimiento presunto. Pasados los seis meses, recibida la prueba y oído el defensor, el juez debe declarar el fallecimiento presunto si están acreditados los extremos legal'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['declaracin', 'fallecimiento', 'presunto', 'articulo 89'], segments: [], amendments: [] },
  { id: 'ccyc-art-90', lawId: 'codigo-civil-comercial', number: '90', order: 90, title: "Día presuntivo del fallecimiento", originalText: "Día presuntivo del fallecimiento. Debe fijarse como día presuntivo del fallecimiento: a) en el caso ordinario, el último día del primer año y medio; b) en el primero de los casos extraordinarios, el día del suceso, y si no está determinado, el día del término medio de la época en que ocurrió o pudo haber ocurrido; c) en el segundo caso extraordinario, el último día en que se tuvo noticia del buque o aeronave perdidos; d) si es posible, la sentencia debe determinar también la hora presuntiva del fallecimiento; en caso contrario, se tiene por sucedido a la expiración del día declarado como presuntivo del fallecimiento.", currentText: "Día presuntivo del fallecimiento. Debe fijarse como día presuntivo del fallecimiento: a) en el caso ordinario, el último día del primer año y medio; b) en el primero de los casos extraordinarios, el día del suceso, y si no está determinado, el día del término medio de la época en que ocurrió o pudo haber ocurrido; c) en el segundo caso extraordinario, el último día en que se tuvo noticia del buque o aeronave perdidos; d) si es posible, la sentencia debe determinar también la hora presuntiva del fallecimiento; en caso contrario, se tiene por sucedido a la expiración del día declarado como presuntivo del fallecimiento.", plainLanguageExplanation: "Establece el régimen de día presuntivo del fallecimiento. Debe fijarse como día presuntivo del fallecimiento: a) en el caso ordinario, el último día del primer año y medio; b) en el primero de los casos extraordinarios, el día del suceso, y si no está determinado, el día del término medio de la época en que ocurrió o pudo haber ocurrido", practicalEffects: ['En la práctica, este artículo rige día presuntivo del fallecimiento. Debe fijarse como día presuntivo del fallecimiento: a) en el caso ordinario, el último día del primer año y medio; b) en el primero de los casos extra'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presuntivo', 'fallecimiento', 'articulo 90'], segments: [], amendments: [] },
  { id: 'ccyc-art-91', lawId: 'codigo-civil-comercial', number: '91', order: 91, title: "Entrega de los bienes", originalText: "Entrega de los bienes. Inventario. Los herederos y los legatarios deben recibir los bienes del declarado presuntamente fallecido, previa formación de inventario. El dominio debe inscribirse en el registro correspondiente con la prenotación del caso; puede hacerse la partición de los bienes, pero no enajenarlos ni gravarlos sin autorización judicial. Si entregados los bienes se presenta el ausente o se tiene noticia cierta de su existencia, queda sin efecto la declaración de fallecimiento, procediéndose a la devolución de aquéllos a petición del interesado.", currentText: "Entrega de los bienes. Inventario. Los herederos y los legatarios deben recibir los bienes del declarado presuntamente fallecido, previa formación de inventario. El dominio debe inscribirse en el registro correspondiente con la prenotación del caso; puede hacerse la partición de los bienes, pero no enajenarlos ni gravarlos sin autorización judicial. Si entregados los bienes se presenta el ausente o se tiene noticia cierta de su existencia, queda sin efecto la declaración de fallecimiento, procediéndose a la devolución de aquéllos a petición del interesado.", plainLanguageExplanation: "Establece el régimen de entrega de los bienes. Inventario.", practicalEffects: ['En la práctica, este artículo rige entrega de los bienes. Inventario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['entrega', 'bienes', 'articulo 91'], segments: [], amendments: [] },
  { id: 'ccyc-art-92', lawId: 'codigo-civil-comercial', number: '92', order: 92, title: "Conclusión de la prenotación", originalText: "Conclusión de la prenotación. La prenotación queda sin efecto transcurridos cinco años desde la fecha presuntiva del fallecimiento u ochenta años desde el nacimiento de la persona. Desde ese momento puede disponerse libremente de los bienes. Si el ausente reaparece puede reclamar: a) la entrega de los bienes que existen en el estado en que se encuentran; b) los adquiridos con el valor de los que faltan; c) el precio adeudado de los enajenados; d) los frutos no consumidos. CAPITULO 8 Fin de la existencia de las personas", currentText: "Conclusión de la prenotación. La prenotación queda sin efecto transcurridos cinco años desde la fecha presuntiva del fallecimiento u ochenta años desde el nacimiento de la persona. Desde ese momento puede disponerse libremente de los bienes. Si el ausente reaparece puede reclamar: a) la entrega de los bienes que existen en el estado en que se encuentran; b) los adquiridos con el valor de los que faltan; c) el precio adeudado de los enajenados; d) los frutos no consumidos. CAPITULO 8 Fin de la existencia de las personas", plainLanguageExplanation: "Establece el régimen de conclusión de la prenotación. La prenotación queda sin efecto transcurridos cinco años desde la fecha presuntiva del fallecimiento u ochenta años desde el nacimiento de la persona.", practicalEffects: ['En la práctica, este artículo rige conclusión de la prenotación. La prenotación queda sin efecto transcurridos cinco años desde la fecha presuntiva del fallecimiento u ochenta años desde el nacimiento de la persona.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conclusin', 'prenotacin', 'articulo 92'], segments: [], amendments: [] },
  { id: 'ccyc-art-93', lawId: 'codigo-civil-comercial', number: '93', order: 93, title: "Principio general", originalText: "Principio general. La existencia de la persona humana termina por su muerte.", currentText: "Principio general. La existencia de la persona humana termina por su muerte.", plainLanguageExplanation: "Establece el régimen de principio general. La existencia de la persona humana termina por su muerte.", practicalEffects: ['En la práctica, este artículo rige principio general. La existencia de la persona humana termina por su muerte.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['principio', 'general', 'articulo 93'], segments: [], amendments: [] },
  { id: 'ccyc-art-94', lawId: 'codigo-civil-comercial', number: '94', order: 94, title: "Comprobación de la muerte", originalText: "Comprobación de la muerte. La comprobación de la muerte queda sujeta a los estándares médicos aceptados, aplicándose la legislación especial en el caso de ablación de órganos del cadáver.", currentText: "Comprobación de la muerte. La comprobación de la muerte queda sujeta a los estándares médicos aceptados, aplicándose la legislación especial en el caso de ablación de órganos del cadáver.", plainLanguageExplanation: "Establece el régimen de comprobación de la muerte. La comprobación de la muerte queda sujeta a los estándares médicos aceptados, aplicándose la legislación especial en el caso de ablación de órganos del cadáver.", practicalEffects: ['En la práctica, este artículo rige comprobación de la muerte. La comprobación de la muerte queda sujeta a los estándares médicos aceptados, aplicándose la legislación especial en el caso de ablación de órganos de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['comprobacin', 'muerte', 'articulo 94'], segments: [], amendments: [] },
  { id: 'ccyc-art-95', lawId: 'codigo-civil-comercial', number: '95', order: 95, title: "Conmoriencia", originalText: "Conmoriencia. Se presume que mueren al mismo tiempo las personas que perecen en un desastre común o en cualquier otra circunstancia, si no puede determinarse lo contrario. CAPITULO 9 Prueba del nacimiento, de la muerte y de la edad", currentText: "Conmoriencia. Se presume que mueren al mismo tiempo las personas que perecen en un desastre común o en cualquier otra circunstancia, si no puede determinarse lo contrario. CAPITULO 9 Prueba del nacimiento, de la muerte y de la edad", plainLanguageExplanation: "Establece el régimen de conmoriencia. Se presume que mueren al mismo tiempo las personas que perecen en un desastre común o en cualquier otra circunstancia, si no puede determinarse lo contrario.", practicalEffects: ['En la práctica, este artículo rige conmoriencia. Se presume que mueren al mismo tiempo las personas que perecen en un desastre común o en cualquier otra circunstancia, si no puede determinarse lo contrario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conmorienciaarticulo 95'], segments: [], amendments: [] },
  { id: 'ccyc-art-96', lawId: 'codigo-civil-comercial', number: '96', order: 96, title: "Medio de prueba", originalText: "Medio de prueba. El nacimiento ocurrido en la República, sus circunstancias de tiempo y lugar, el sexo, el nombre y la filiación de las personas nacidas, se prueba con las partidas del Registro Civil. Del mismo modo se prueba la muerte de las personas fallecidas en la República. La rectificación de las partidas se hace conforme a lo dispuesto en la legislación especial.", currentText: "Medio de prueba. El nacimiento ocurrido en la República, sus circunstancias de tiempo y lugar, el sexo, el nombre y la filiación de las personas nacidas, se prueba con las partidas del Registro Civil. Del mismo modo se prueba la muerte de las personas fallecidas en la República. La rectificación de las partidas se hace conforme a lo dispuesto en la legislación especial.", plainLanguageExplanation: "Establece el régimen de medio de prueba. El nacimiento ocurrido en la República, sus circunstancias de tiempo y lugar, el sexo, el nombre y la filiación de las personas nacidas, se prueba con las partidas del Registro Civil.", practicalEffects: ['En la práctica, este artículo rige medio de prueba. El nacimiento ocurrido en la República, sus circunstancias de tiempo y lugar, el sexo, el nombre y la filiación de las personas nacidas, se prueba con las partidas del Registro Civil.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medio', 'prueba', 'articulo 96'], segments: [], amendments: [] },
  { id: 'ccyc-art-97', lawId: 'codigo-civil-comercial', number: '97', order: 97, title: "Nacimiento o muerte ocurridos en el extranjero", originalText: "Nacimiento o muerte ocurridos en el extranjero. El nacimiento o la muerte ocurridos en el extranjero se prueban con los instrumentos otorgados según las leyes del lugar donde se producen, legalizados o autenticados del modo que disponen las convenciones internacionales, y a falta de convenciones, por las disposiciones consulares de la República. Los certificados de los asientos practicados en los registros consulares argentinos son suficientes para probar el nacimiento de los hijos de argentinos y para acreditar la muerte de los ciudadanos argentinos.", currentText: "Nacimiento o muerte ocurridos en el extranjero. El nacimiento o la muerte ocurridos en el extranjero se prueban con los instrumentos otorgados según las leyes del lugar donde se producen, legalizados o autenticados del modo que disponen las convenciones internacionales, y a falta de convenciones, por las disposiciones consulares de la República. Los certificados de los asientos practicados en los registros consulares argentinos son suficientes para probar el nacimiento de los hijos de argentinos y para acreditar la muerte de los ciudadanos argentinos.", plainLanguageExplanation: "Establece el régimen de nacimiento o muerte ocurridos en el extranjero. El nacimiento o la muerte ocurridos en el extranjero se prueban con los instrumentos otorgados según las leyes del lugar donde se producen, legalizados o autenticados del modo que disponen las convenciones internacionales, y a falta de convenciones, por las disposiciones consulares de la República.", practicalEffects: ['En la práctica, este artículo rige nacimiento o muerte ocurridos en el extranjero. El nacimiento o la muerte ocurridos en el extranjero se prueban con los instrumentos otorgados según las leyes del lugar donde se producen, legalizado'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['nacimiento', 'muerte', 'ocurridos', 'extranjero', 'articulo 97'], segments: [], amendments: [] },
  { id: 'ccyc-art-98', lawId: 'codigo-civil-comercial', number: '98', order: 98, title: "Falta de registro o nulidad del asiento", originalText: "Falta de registro o nulidad del asiento. Si no hay registro público o falta o es nulo el asiento, el nacimiento y la muerte pueden acreditarse por otros medios de prueba. Si el cadáver de una persona no es hallado o no puede ser identificado, el juez puede tener por comprobada la muerte y disponer la pertinente inscripción en el registro, si la desaparición se produjo en circunstancias tales que la muerte debe ser tenida como cierta.", currentText: "Falta de registro o nulidad del asiento. Si no hay registro público o falta o es nulo el asiento, el nacimiento y la muerte pueden acreditarse por otros medios de prueba. Si el cadáver de una persona no es hallado o no puede ser identificado, el juez puede tener por comprobada la muerte y disponer la pertinente inscripción en el registro, si la desaparición se produjo en circunstancias tales que la muerte debe ser tenida como cierta.", plainLanguageExplanation: "Establece el régimen de falta de registro o nulidad del asiento. Si no hay registro público o falta o es nulo el asiento, el nacimiento y la muerte pueden acreditarse por otros medios de prueba.", practicalEffects: ['En la práctica, este artículo rige falta de registro o nulidad del asiento. Si no hay registro público o falta o es nulo el asiento, el nacimiento y la muerte pueden acreditarse por otros medios de prueba.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['falta', 'registro', 'nulidad', 'asiento', 'articulo 98'], segments: [], amendments: [] },
  { id: 'ccyc-art-99', lawId: 'codigo-civil-comercial', number: '99', order: 99, title: "Determinación de la edad", originalText: "Determinación de la edad. Si no es posible establecer la edad de las personas por los medios indicados en el presente Capítulo, se la debe determinar judicialmente previo dictamen de peritos. CAPITULO 10 Representación y asistencia. Tutela y curatela SECCION 1ª Representación y asistencia", currentText: "Determinación de la edad. Si no es posible establecer la edad de las personas por los medios indicados en el presente Capítulo, se la debe determinar judicialmente previo dictamen de peritos. CAPITULO 10 Representación y asistencia. Tutela y curatela SECCION 1ª Representación y asistencia", plainLanguageExplanation: "Establece el régimen de determinación de la edad. Si no es posible establecer la edad de las personas por los medios indicados en el presente Capítulo, se la debe determinar judicialmente previo dictamen de peritos.", practicalEffects: ['En la práctica, este artículo rige determinación de la edad. Si no es posible establecer la edad de las personas por los medios indicados en el presente Capítulo, se la debe determinar judicialmente previo dictamen de peritos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['determinacin', 'edad', 'articulo 99'], segments: [], amendments: [] },
  { id: 'ccyc-art-100', lawId: 'codigo-civil-comercial', number: '100', order: 100, title: "Regla general", originalText: "Regla general. Las personas incapaces ejercen por medio de sus representantes los derechos que no pueden ejercer por sí.", currentText: "Regla general. Las personas incapaces ejercen por medio de sus representantes los derechos que no pueden ejercer por sí.", plainLanguageExplanation: "Establece el régimen de regla general. Las personas incapaces ejercen por medio de sus representantes los derechos que no pueden ejercer por sí.", practicalEffects: ['En la práctica, este artículo rige regla general. Las personas incapaces ejercen por medio de sus representantes los derechos que no pueden ejercer por sí.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['regla', 'general', 'articulo 100'], segments: [], amendments: [] },
  { id: 'ccyc-art-101', lawId: 'codigo-civil-comercial', number: '101', order: 101, title: "Enumeración", originalText: "Enumeración. Son representantes: a) de las personas por nacer, sus padres; b) de las personas menores de edad no emancipadas, sus padres. Si faltan los padres, o ambos son incapaces, o están privados de la responsabilidad parental, o suspendidos en su ejercicio, el tutor que se les designe; c) de las personas con capacidad restringida, el o los apoyos designados cuando, conforme a la sentencia, éstos tengan representación para determinados actos; de las personas incapaces en los términos del último párrafo del artículo 32, el curador que se les nombre.", currentText: "Enumeración. Son representantes: a) de las personas por nacer, sus padres; b) de las personas menores de edad no emancipadas, sus padres. Si faltan los padres, o ambos son incapaces, o están privados de la responsabilidad parental, o suspendidos en su ejercicio, el tutor que se les designe; c) de las personas con capacidad restringida, el o los apoyos designados cuando, conforme a la sentencia, éstos tengan representación para determinados actos; de las personas incapaces en los términos del último párrafo del artículo 32, el curador que se les nombre.", plainLanguageExplanation: "Establece el régimen de enumeración. Son representantes: a) de las personas por nacer, sus padres; b) de las personas menores de edad no emancipadas, sus padres.", practicalEffects: ['En la práctica, este artículo rige enumeración. Son representantes: a) de las personas por nacer, sus padres; b) de las personas menores de edad no emancipadas, sus padres.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['enumeracinarticulo 101'], segments: [], amendments: [] },
  { id: 'ccyc-art-102', lawId: 'codigo-civil-comercial', number: '102', order: 102, title: "Asistencia", originalText: "Asistencia. Las personas con capacidad restringida y las inhabilitadas son asistidas por los apoyos designados en la sentencia respectiva y en otras leyes especiales.", currentText: "Asistencia. Las personas con capacidad restringida y las inhabilitadas son asistidas por los apoyos designados en la sentencia respectiva y en otras leyes especiales.", plainLanguageExplanation: "Establece el régimen de asistencia. Las personas con capacidad restringida y las inhabilitadas son asistidas por los apoyos designados en la sentencia respectiva y en otras leyes especiales.", practicalEffects: ['En la práctica, este artículo rige asistencia. Las personas con capacidad restringida y las inhabilitadas son asistidas por los apoyos designados en la sentencia respectiva y en otras leyes especia'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['asistenciaarticulo 102'], segments: [], amendments: [] },
  { id: 'ccyc-art-103', lawId: 'codigo-civil-comercial', number: '103', order: 103, title: "Actuación del Ministerio Público", originalText: "Actuación del Ministerio Público. La actuación del Ministerio Público respecto de personas menores de edad, incapaces y con capacidad restringida, y de aquellas cuyo ejercicio de capacidad requiera de un sistema de apoyos puede ser, en el ámbito judicial, complementaria o principal. a) Es complementaria en todos los procesos en los que se encuentran involucrados intereses de personas menores de edad, incapaces y con capacidad restringida; la falta de intervención causa la nulidad relativa del acto. b) Es principal: i) cuando los derechos de los representados están comprometidos, y existe inacción de los representantes; ii) cuando el objeto del proceso es exigir el cumplimiento de los deberes a cargo de los representantes; iii) cuando carecen de representante legal y es necesario proveer la representación. En el ámbito extrajudicial, el Ministerio Público actúa ante la ausencia, carencia o inacción de los representantes legales, cuando están comprometidos los derechos sociales, económicos y culturales. SECCION 2ª Tutela Parágrafo 1° Disposiciones generales", currentText: "Actuación del Ministerio Público. La actuación del Ministerio Público respecto de personas menores de edad, incapaces y con capacidad restringida, y de aquellas cuyo ejercicio de capacidad requiera de un sistema de apoyos puede ser, en el ámbito judicial, complementaria o principal. a) Es complementaria en todos los procesos en los que se encuentran involucrados intereses de personas menores de edad, incapaces y con capacidad restringida; la falta de intervención causa la nulidad relativa del acto. b) Es principal: i) cuando los derechos de los representados están comprometidos, y existe inacción de los representantes; ii) cuando el objeto del proceso es exigir el cumplimiento de los deberes a cargo de los representantes; iii) cuando carecen de representante legal y es necesario proveer la representación. En el ámbito extrajudicial, el Ministerio Público actúa ante la ausencia, carencia o inacción de los representantes legales, cuando están comprometidos los derechos sociales, económicos y culturales. SECCION 2ª Tutela Parágrafo 1° Disposiciones generales", plainLanguageExplanation: "Establece el régimen de actuación del ministerio público. La actuación del Ministerio Público respecto de personas menores de edad, incapaces y con capacidad restringida, y de aquellas cuyo ejercicio de capacidad requiera de un sistema de apoyos puede ser, en el ámbito judicial, complementaria o principal.", practicalEffects: ['En la práctica, este artículo rige actuación del ministerio público. La actuación del Ministerio Público respecto de personas menores de edad, incapaces y con capacidad restringida, y de aquellas cuyo ejercicio de capac'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actuacin', 'ministerio', 'pblico', 'articulo 103'], segments: [], amendments: [] },
  { id: 'ccyc-art-104', lawId: 'codigo-civil-comercial', number: '104', order: 104, title: "Concepto y principios generales", originalText: "Concepto y principios generales. La tutela está destinada a brindar protección a la persona y bienes de un niño, niña o adolescente que no ha alcanzado la plenitud de su capacidad civil cuando no haya persona que ejerza la responsabilidad parental. Se aplican los principios generales enumerados en el Título VII del Libro Segundo. Si se hubiera otorgado la guarda a un pariente de conformidad con lo previsto en el Título de la responsabilidad parental, la protección de la persona y bienes del niño, niña y adolescente puede quedar a cargo del guardador por decisión del juez que otorgó la guarda, si ello es más beneficioso para su interés superior; en igual sentido, si los titulares de la responsabilidad parental delegaron su ejercicio a un pariente. En este caso, el juez que homologó la delegación puede otorgar las funciones de protección de la persona y bienes de los niños, niñas y adolescentes a quienes los titulares delegaron su ejercicio. En ambos supuestos, el guardador es el representante legal del niño, niña o adolescente en todas aquellas cuestiones de carácter patrimonial.", currentText: "Concepto y principios generales. La tutela está destinada a brindar protección a la persona y bienes de un niño, niña o adolescente que no ha alcanzado la plenitud de su capacidad civil cuando no haya persona que ejerza la responsabilidad parental. Se aplican los principios generales enumerados en el Título VII del Libro Segundo. Si se hubiera otorgado la guarda a un pariente de conformidad con lo previsto en el Título de la responsabilidad parental, la protección de la persona y bienes del niño, niña y adolescente puede quedar a cargo del guardador por decisión del juez que otorgó la guarda, si ello es más beneficioso para su interés superior; en igual sentido, si los titulares de la responsabilidad parental delegaron su ejercicio a un pariente. En este caso, el juez que homologó la delegación puede otorgar las funciones de protección de la persona y bienes de los niños, niñas y adolescentes a quienes los titulares delegaron su ejercicio. En ambos supuestos, el guardador es el representante legal del niño, niña o adolescente en todas aquellas cuestiones de carácter patrimonial.", plainLanguageExplanation: "Establece el régimen de concepto y principios generales. La tutela está destinada a brindar protección a la persona y bienes de un niño, niña o adolescente que no ha alcanzado la plenitud de su capacidad civil cuando no haya persona que ejerza la responsabilidad parental.", practicalEffects: ['En la práctica, este artículo rige concepto y principios generales. La tutela está destinada a brindar protección a la persona y bienes de un niño, niña o adolescente que no ha alcanzado la plenitud de su capacidad civ'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['concepto', 'principios', 'generales', 'articulo 104'], segments: [], amendments: [] },
  { id: 'ccyc-art-105', lawId: 'codigo-civil-comercial', number: '105', order: 105, title: "Caracteres", originalText: "Caracteres. La tutela puede ser ejercida por una o más personas, conforme aquello que más beneficie al niño, niña o adolescente. Si es ejercida por más de una persona, las diferencias de criterio, deben ser dirimidas ante el juez que haya discernido la tutela, con la debida intervención del Ministerio Público. El cargo de tutor es intransmisible; el Ministerio Público interviene según lo dispuesto en el artículo 103.", currentText: "Caracteres. La tutela puede ser ejercida por una o más personas, conforme aquello que más beneficie al niño, niña o adolescente. Si es ejercida por más de una persona, las diferencias de criterio, deben ser dirimidas ante el juez que haya discernido la tutela, con la debida intervención del Ministerio Público. El cargo de tutor es intransmisible; el Ministerio Público interviene según lo dispuesto en el artículo 103.", plainLanguageExplanation: "Establece el régimen de caracteres. La tutela puede ser ejercida por una o más personas, conforme aquello que más beneficie al niño, niña o adolescente.", practicalEffects: ['En la práctica, este artículo rige caracteres. La tutela puede ser ejercida por una o más personas, conforme aquello que más beneficie al niño, niña o adolescente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caracteresarticulo 105'], segments: [], amendments: [] },
  { id: 'ccyc-art-106', lawId: 'codigo-civil-comercial', number: '106', order: 106, title: "Tutor designado por los padres", originalText: "Tutor designado por los padres. Cualquiera de los padres que no se encuentre privado o suspendido del ejercicio de la responsabilidad parental puede nombrar tutor o tutores a sus hijos menores de edad, sea por testamento o por escritura pública. Esta designación debe ser aprobada judicialmente. Se tienen por no escritas las disposiciones que eximen al tutor de hacer inventario, lo autorizan a recibir los bienes sin cumplir ese requisito, o lo liberan del deber de rendir cuentas. Si los padres hubieran delegado el ejercicio de la responsabilidad parental en un pariente, se presume la voluntad de que se lo nombre tutor de sus hijos menores de edad, designación que debe ser discernida por el juez que homologó la delegación o el del centro de vida del niño, niña o adolescente, a elección del pariente. Si existen disposiciones de ambos progenitores, se aplican unas y otras conjuntamente en cuanto sean compatibles. De no serlo, el juez debe adoptar las que considere fundadamente más convenientes para el tutelado.", currentText: "Tutor designado por los padres. Cualquiera de los padres que no se encuentre privado o suspendido del ejercicio de la responsabilidad parental puede nombrar tutor o tutores a sus hijos menores de edad, sea por testamento o por escritura pública. Esta designación debe ser aprobada judicialmente. Se tienen por no escritas las disposiciones que eximen al tutor de hacer inventario, lo autorizan a recibir los bienes sin cumplir ese requisito, o lo liberan del deber de rendir cuentas. Si los padres hubieran delegado el ejercicio de la responsabilidad parental en un pariente, se presume la voluntad de que se lo nombre tutor de sus hijos menores de edad, designación que debe ser discernida por el juez que homologó la delegación o el del centro de vida del niño, niña o adolescente, a elección del pariente. Si existen disposiciones de ambos progenitores, se aplican unas y otras conjuntamente en cuanto sean compatibles. De no serlo, el juez debe adoptar las que considere fundadamente más convenientes para el tutelado.", plainLanguageExplanation: "Establece el régimen de tutor designado por los padres. Cualquiera de los padres que no se encuentre privado o suspendido del ejercicio de la responsabilidad parental puede nombrar tutor o tutores a sus hijos menores de edad, sea por testamento o por escritura pública.", practicalEffects: ['En la práctica, este artículo rige tutor designado por los padres. Cualquiera de los padres que no se encuentre privado o suspendido del ejercicio de la responsabilidad parental puede nombrar tutor o tutores a sus hij'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tutor', 'designado', 'padres', 'articulo 106'], segments: [], amendments: [] },
  { id: 'ccyc-art-107', lawId: 'codigo-civil-comercial', number: '107', order: 107, title: "Tutela dativa", originalText: "Tutela dativa. Ante la ausencia de designación paterna de tutor o tutores o ante la excusación, rechazo o imposibilidad de ejercicio de aquellos designados, el juez debe otorgar la tutela a la persona que sea más idónea para brindar protección al niño, niña o adolescente, debiendo fundar razonablemente los motivos que justifican dicha idoneidad.", currentText: "Tutela dativa. Ante la ausencia de designación paterna de tutor o tutores o ante la excusación, rechazo o imposibilidad de ejercicio de aquellos designados, el juez debe otorgar la tutela a la persona que sea más idónea para brindar protección al niño, niña o adolescente, debiendo fundar razonablemente los motivos que justifican dicha idoneidad.", plainLanguageExplanation: "Establece el régimen de tutela dativa. Ante la ausencia de designación paterna de tutor o tutores o ante la excusación, rechazo o imposibilidad de ejercicio de aquellos designados, el juez debe otorgar la tutela a la persona que sea más idónea para brindar protección al niño, niña o adolescente, debiendo fundar razona", practicalEffects: ['En la práctica, este artículo rige tutela dativa. Ante la ausencia de designación paterna de tutor o tutores o ante la excusación, rechazo o imposibilidad de ejercicio de aquellos designados, el juez'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tutela', 'dativa', 'articulo 107'], segments: [], amendments: [] },
  { id: 'ccyc-art-108', lawId: 'codigo-civil-comercial', number: '108', order: 108, title: "Prohibiciones para ser tutor dativo", originalText: "Prohibiciones para ser tutor dativo. El juez no puede conferir la tutela dativa: a) a su cónyuge, conviviente, o parientes dentro del cuarto grado, o segundo por afinidad; b) a las personas con quienes mantiene amistad íntima ni a los parientes dentro del cuarto grado, o segundo por afinidad; c) a las personas con quienes tiene intereses comunes; d) a sus deudores o acreedores; e) a los integrantes de los tribunales nacionales o provinciales que ejercen sus funciones en el lugar del nombramiento; ni a los que tienen con ellos intereses comunes, ni a sus amigos íntimos o los parientes de éstos, dentro del cuarto grado, o segundo por afinidad; f) a quien es tutor de otro menor de edad, a menos que se trate de hermanos menores de edad, o existan causas que lo justifiquen.", currentText: "Prohibiciones para ser tutor dativo. El juez no puede conferir la tutela dativa: a) a su cónyuge, conviviente, o parientes dentro del cuarto grado, o segundo por afinidad; b) a las personas con quienes mantiene amistad íntima ni a los parientes dentro del cuarto grado, o segundo por afinidad; c) a las personas con quienes tiene intereses comunes; d) a sus deudores o acreedores; e) a los integrantes de los tribunales nacionales o provinciales que ejercen sus funciones en el lugar del nombramiento; ni a los que tienen con ellos intereses comunes, ni a sus amigos íntimos o los parientes de éstos, dentro del cuarto grado, o segundo por afinidad; f) a quien es tutor de otro menor de edad, a menos que se trate de hermanos menores de edad, o existan causas que lo justifiquen.", plainLanguageExplanation: "Establece el régimen de prohibiciones para ser tutor dativo. El juez no puede conferir la tutela dativa: a) a su cónyuge, conviviente, o parientes dentro del cuarto grado, o segundo por afinidad; b) a las personas con quienes mantiene amistad íntima ni a los parientes dentro del cuarto grado, o segundo por afinidad; c) a las personas con q", practicalEffects: ['En la práctica, este artículo rige prohibiciones para ser tutor dativo. El juez no puede conferir la tutela dativa: a) a su cónyuge, conviviente, o parientes dentro del cuarto grado, o segundo por afinidad; b) a las person'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prohibiciones', 'para', 'tutor', 'dativo', 'articulo 108'], segments: [], amendments: [] },
  { id: 'ccyc-art-109', lawId: 'codigo-civil-comercial', number: '109', order: 109, title: "Tutela especial", originalText: "Tutela especial. Corresponde la designación judicial de tutores especiales en los siguientes casos: a) cuando existe conflicto de intereses entre los representados y sus representantes; si el representado es un adolescente puede actuar por sí, con asistencia letrada, en cuyo caso el juez puede decidir que no es necesaria la designación del tutor especial; b) cuando los padres no tienen la administración de los bienes de los hijos menores de edad; c) cuando existe oposición de intereses entre diversas personas incapaces que tienen un mismo representante legal, sea padre, madre, tutor o curador; si las personas incapaces son adolescentes, rige lo dispuesto en el inciso a); d) cuando la persona sujeta a tutela hubiera adquirido bienes con la condición de ser administrados por persona determinada o con la condición de no ser administrados por su tutor; e) cuando existe necesidad de ejercer actos de administración sobre bienes de extraña jurisdicción al juez de la tutela y no pueden ser convenientemente administrados por el tutor; f) cuando se requieren conocimientos específicos o particulares para un adecuado ejercicio de la administración por las características propias del bien a administrar; g) cuando existen razones de urgencia, hasta tanto se tramite la designación del tutor que corresponda.", currentText: "Tutela especial. Corresponde la designación judicial de tutores especiales en los siguientes casos: a) cuando existe conflicto de intereses entre los representados y sus representantes; si el representado es un adolescente puede actuar por sí, con asistencia letrada, en cuyo caso el juez puede decidir que no es necesaria la designación del tutor especial; b) cuando los padres no tienen la administración de los bienes de los hijos menores de edad; c) cuando existe oposición de intereses entre diversas personas incapaces que tienen un mismo representante legal, sea padre, madre, tutor o curador; si las personas incapaces son adolescentes, rige lo dispuesto en el inciso a); d) cuando la persona sujeta a tutela hubiera adquirido bienes con la condición de ser administrados por persona determinada o con la condición de no ser administrados por su tutor; e) cuando existe necesidad de ejercer actos de administración sobre bienes de extraña jurisdicción al juez de la tutela y no pueden ser convenientemente administrados por el tutor; f) cuando se requieren conocimientos específicos o particulares para un adecuado ejercicio de la administración por las características propias del bien a administrar; g) cuando existen razones de urgencia, hasta tanto se tramite la designación del tutor que corresponda.", plainLanguageExplanation: "Establece el régimen de tutela especial. Corresponde la designación judicial de tutores especiales en los siguientes casos: a) cuando existe conflicto de intereses entre los representados y sus representantes; si el representado es un adolescente puede actuar por sí, con asistencia letrada, en cuyo caso el juez puede de", practicalEffects: ['En la práctica, este artículo rige tutela especial. Corresponde la designación judicial de tutores especiales en los siguientes casos: a) cuando existe conflicto de intereses entre los representados y s'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tutela', 'especial', 'articulo 109'], segments: [], amendments: [] },
  { id: 'ccyc-art-110', lawId: 'codigo-civil-comercial', number: '110', order: 110, title: "Personas excluidas", originalText: "Personas excluidas. No pueden ser tutores las personas: a) que no tienen domicilio en la República; b) quebradas no rehabilitadas; c) que han sido privadas o suspendidas en el ejercicio de la responsabilidad parental, o han sido removidas de la tutela o curatela o apoyo de otra persona incapaz o con capacidad restringida, por causa que les era atribuible; d) que deben ejercer por largo tiempo o plazo indefinido un cargo o comisión fuera del país; e) que no tienen oficio, profesión o modo de vivir conocido, o tienen mala conducta notoria; f) condenadas por delito doloso a penas privativas de la libertad; g) deudoras o acreedoras por sumas considerables respecto de la persona sujeta a tutela; h) que tienen pleitos con quien requiere la designación de un tutor. La prohibición se extiende a su cónyuge, conviviente, padres o hijos; i) que, estando obligadas, omiten la denuncia de los hechos que dan lugar a la apertura de la tutela; j) inhabilitadas, incapaces o con capacidad restringida; k) que hubieran sido expresamente excluidas por el padre o la madre de quien requiere la tutela, excepto que según el criterio del juez resulte beneficioso para el niño, niña o adolescente.", currentText: "Personas excluidas. No pueden ser tutores las personas: a) que no tienen domicilio en la República; b) quebradas no rehabilitadas; c) que han sido privadas o suspendidas en el ejercicio de la responsabilidad parental, o han sido removidas de la tutela o curatela o apoyo de otra persona incapaz o con capacidad restringida, por causa que les era atribuible; d) que deben ejercer por largo tiempo o plazo indefinido un cargo o comisión fuera del país; e) que no tienen oficio, profesión o modo de vivir conocido, o tienen mala conducta notoria; f) condenadas por delito doloso a penas privativas de la libertad; g) deudoras o acreedoras por sumas considerables respecto de la persona sujeta a tutela; h) que tienen pleitos con quien requiere la designación de un tutor. La prohibición se extiende a su cónyuge, conviviente, padres o hijos; i) que, estando obligadas, omiten la denuncia de los hechos que dan lugar a la apertura de la tutela; j) inhabilitadas, incapaces o con capacidad restringida; k) que hubieran sido expresamente excluidas por el padre o la madre de quien requiere la tutela, excepto que según el criterio del juez resulte beneficioso para el niño, niña o adolescente.", plainLanguageExplanation: "Establece el régimen de personas excluidas. No pueden ser tutores las personas: a) que no tienen domicilio en la República; b) quebradas no rehabilitadas; c) que han sido privadas o suspendidas en el ejercicio de la responsabilidad parental, o han sido removidas de la tutela o curatela o apoyo de otra persona incapaz o con", practicalEffects: ['En la práctica, este artículo rige personas excluidas. No pueden ser tutores las personas: a) que no tienen domicilio en la República; b) quebradas no rehabilitadas; c) que han sido privadas o suspendidas'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['personas', 'excluidas', 'articulo 110'], segments: [], amendments: [] },
  { id: 'ccyc-art-111', lawId: 'codigo-civil-comercial', number: '111', order: 111, title: "Obligados a denunciar", originalText: "Obligados a denunciar. Los parientes obligados a prestar alimentos al niño, niña o adolescente, el guardador o quienes han sido designados tutores por sus padres o éstos les hayan delegado el ejercicio de la responsabilidad parental, deben denunciar a la autoridad competente que el niño, niña o adolescente no tiene referente adulto que lo proteja, dentro de los diez días de haber conocido esta circunstancia, bajo pena de ser privados de la posibilidad de ser designados tutores y ser responsables de los daños y perjuicios que su omisión de denunciar le ocasione al niño, niña o adolescente. Tienen la misma obligación los oficiales públicos encargados del Registro de Estado Civil y Capacidad de las Personas y otros funcionarios públicos que, en ejercicio de su cargo, tengan conocimiento de cualquier hecho que dé lugar a la necesidad de la tutela. El juez debe proveer de oficio lo que corresponda, cuando tenga conocimiento de un hecho que motive la apertura de una tutela. Parágrafo 2° Discernimiento de la tutela", currentText: "Obligados a denunciar. Los parientes obligados a prestar alimentos al niño, niña o adolescente, el guardador o quienes han sido designados tutores por sus padres o éstos les hayan delegado el ejercicio de la responsabilidad parental, deben denunciar a la autoridad competente que el niño, niña o adolescente no tiene referente adulto que lo proteja, dentro de los diez días de haber conocido esta circunstancia, bajo pena de ser privados de la posibilidad de ser designados tutores y ser responsables de los daños y perjuicios que su omisión de denunciar le ocasione al niño, niña o adolescente. Tienen la misma obligación los oficiales públicos encargados del Registro de Estado Civil y Capacidad de las Personas y otros funcionarios públicos que, en ejercicio de su cargo, tengan conocimiento de cualquier hecho que dé lugar a la necesidad de la tutela. El juez debe proveer de oficio lo que corresponda, cuando tenga conocimiento de un hecho que motive la apertura de una tutela. Parágrafo 2° Discernimiento de la tutela", plainLanguageExplanation: "Establece el régimen de obligados a denunciar. Los parientes obligados a prestar alimentos al niño, niña o adolescente, el guardador o quienes han sido designados tutores por sus padres o éstos les hayan delegado el ejercicio de la responsabilidad parental, deben denunciar a la autoridad competente que el niño, niña o adolesc", practicalEffects: ['En la práctica, este artículo rige obligados a denunciar. Los parientes obligados a prestar alimentos al niño, niña o adolescente, el guardador o quienes han sido designados tutores por sus padres o éstos les'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligados', 'denunciar', 'articulo 111'], segments: [], amendments: [] },
  { id: 'ccyc-art-112', lawId: 'codigo-civil-comercial', number: '112', order: 112, title: "Discernimiento judicial", originalText: "Discernimiento judicial. Competencia. La tutela es siempre discernida judicialmente. Para el discernimiento de la tutela es competente el juez del lugar donde el niño, niña o adolescente tiene su centro de vida.", currentText: "Discernimiento judicial. Competencia. La tutela es siempre discernida judicialmente. Para el discernimiento de la tutela es competente el juez del lugar donde el niño, niña o adolescente tiene su centro de vida.", plainLanguageExplanation: "Establece el régimen de discernimiento judicial. Competencia.", practicalEffects: ['En la práctica, este artículo rige discernimiento judicial. Competencia.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['discernimiento', 'judicial', 'articulo 112'], segments: [], amendments: [] },
  { id: 'ccyc-art-113', lawId: 'codigo-civil-comercial', number: '113', order: 113, title: "Audiencia con la persona menor de edad", originalText: "Audiencia con la persona menor de edad. Para el discernimiento de la tutela, y para cualquier otra decisión relativa a la persona menor de edad, el juez debe: a) oír previamente al niño, niña o adolescente; b) tener en cuenta sus manifestaciones en función de su edad y madurez; c) decidir atendiendo primordialmente a su interés superior.", currentText: "Audiencia con la persona menor de edad. Para el discernimiento de la tutela, y para cualquier otra decisión relativa a la persona menor de edad, el juez debe: a) oír previamente al niño, niña o adolescente; b) tener en cuenta sus manifestaciones en función de su edad y madurez; c) decidir atendiendo primordialmente a su interés superior.", plainLanguageExplanation: "Establece el régimen de audiencia con la persona menor de edad. Para el discernimiento de la tutela, y para cualquier otra decisión relativa a la persona menor de edad, el juez debe: a) oír previamente al niño, niña o adolescente; b) tener en cuenta sus manifestaciones en función de su edad y madurez; c) decidir atendiendo primordialmente a s", practicalEffects: ['En la práctica, este artículo rige audiencia con la persona menor de edad. Para el discernimiento de la tutela, y para cualquier otra decisión relativa a la persona menor de edad, el juez debe: a) oír previamente al niño, niñ'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['audiencia', 'persona', 'menor', 'edad', 'articulo 113'], segments: [], amendments: [] },
  { id: 'ccyc-art-114', lawId: 'codigo-civil-comercial', number: '114', order: 114, title: "Actos anteriores al discernimiento de la tutela", originalText: "Actos anteriores al discernimiento de la tutela. Los actos del tutor anteriores al discernimiento de la tutela quedan confirmados por el nombramiento, si de ello no resulta perjuicio para el niño, niña o adolescente.", currentText: "Actos anteriores al discernimiento de la tutela. Los actos del tutor anteriores al discernimiento de la tutela quedan confirmados por el nombramiento, si de ello no resulta perjuicio para el niño, niña o adolescente.", plainLanguageExplanation: "Establece el régimen de actos anteriores al discernimiento de la tutela. Los actos del tutor anteriores al discernimiento de la tutela quedan confirmados por el nombramiento, si de ello no resulta perjuicio para el niño, niña o adolescente.", practicalEffects: ['En la práctica, este artículo rige actos anteriores al discernimiento de la tutela. Los actos del tutor anteriores al discernimiento de la tutela quedan confirmados por el nombramiento, si de ello no resulta perjuicio para el niño, ni'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'anteriores', 'discernimiento', 'tutela', 'articulo 114'], segments: [], amendments: [] },
  { id: 'ccyc-art-115', lawId: 'codigo-civil-comercial', number: '115', order: 115, title: "Inventario y avalúo", originalText: "Inventario y avalúo. Discernida la tutela, los bienes del tutelado deben ser entregados al tutor, previo inventario y avalúo que realiza quien el juez designa. Si el tutor tiene un crédito contra la persona sujeta a tutela, debe hacerlo constar en el inventario; si no lo hace, no puede reclamarlo luego, excepto que al omitirlo haya ignorado su existencia. Hasta tanto se haga el inventario, el tutor sólo puede tomar las medidas que sean urgentes y necesarias. Los bienes que el niño, niña o adolescente adquiera por sucesión u otro título deben inventariarse y tasarse de la misma forma.", currentText: "Inventario y avalúo. Discernida la tutela, los bienes del tutelado deben ser entregados al tutor, previo inventario y avalúo que realiza quien el juez designa. Si el tutor tiene un crédito contra la persona sujeta a tutela, debe hacerlo constar en el inventario; si no lo hace, no puede reclamarlo luego, excepto que al omitirlo haya ignorado su existencia. Hasta tanto se haga el inventario, el tutor sólo puede tomar las medidas que sean urgentes y necesarias. Los bienes que el niño, niña o adolescente adquiera por sucesión u otro título deben inventariarse y tasarse de la misma forma.", plainLanguageExplanation: "Establece el régimen de inventario y avalúo. Discernida la tutela, los bienes del tutelado deben ser entregados al tutor, previo inventario y avalúo que realiza quien el juez designa.", practicalEffects: ['En la práctica, este artículo rige inventario y avalúo. Discernida la tutela, los bienes del tutelado deben ser entregados al tutor, previo inventario y avalúo que realiza quien el juez designa.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inventario', 'avalo', 'articulo 115'], segments: [], amendments: [] },
  { id: 'ccyc-art-116', lawId: 'codigo-civil-comercial', number: '116', order: 116, title: "Rendición de cuentas", originalText: "Rendición de cuentas. Si el tutor sucede a alguno de los padres o a otro tutor anterior, debe pedir inmediatamente, al sustituido o a sus herederos, rendición judicial de cuentas y entrega de los bienes del tutelado. Parágrafo 3° Ejercicio de la tutela", currentText: "Rendición de cuentas. Si el tutor sucede a alguno de los padres o a otro tutor anterior, debe pedir inmediatamente, al sustituido o a sus herederos, rendición judicial de cuentas y entrega de los bienes del tutelado. Parágrafo 3° Ejercicio de la tutela", plainLanguageExplanation: "Establece el régimen de rendición de cuentas. Si el tutor sucede a alguno de los padres o a otro tutor anterior, debe pedir inmediatamente, al sustituido o a sus herederos, rendición judicial de cuentas y entrega de los bienes del tutelado.", practicalEffects: ['En la práctica, este artículo rige rendición de cuentas. Si el tutor sucede a alguno de los padres o a otro tutor anterior, debe pedir inmediatamente, al sustituido o a sus herederos, rendición judicial de cuentas y entrega de los bienes del tutelado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rendicin', 'cuentas', 'articulo 116'], segments: [], amendments: [] },
  { id: 'ccyc-art-117', lawId: 'codigo-civil-comercial', number: '117', order: 117, title: "Ejercicio", originalText: "Ejercicio. Quien ejerce la tutela es representante legal del niño, niña o adolescente en todas aquellas cuestiones de carácter patrimonial, sin perjuicio de su actuación personal en ejercicio de su derecho a ser oído y el progresivo reconocimiento de su capacidad otorgado por la ley o autorizado por el juez.", currentText: "Ejercicio. Quien ejerce la tutela es representante legal del niño, niña o adolescente en todas aquellas cuestiones de carácter patrimonial, sin perjuicio de su actuación personal en ejercicio de su derecho a ser oído y el progresivo reconocimiento de su capacidad otorgado por la ley o autorizado por el juez.", plainLanguageExplanation: "Establece el régimen de ejercicio. Quien ejerce la tutela es representante legal del niño, niña o adolescente en todas aquellas cuestiones de carácter patrimonial, sin perjuicio de su actuación personal en ejercicio de su derecho a ser oído y el progresivo reconocimiento de su capacidad otorgado por la ley o autor", practicalEffects: ['En la práctica, este artículo rige ejercicio. Quien ejerce la tutela es representante legal del niño, niña o adolescente en todas aquellas cuestiones de carácter patrimonial, sin perjuicio de su a'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ejercicioarticulo 117'], segments: [], amendments: [] },
  { id: 'ccyc-art-118', lawId: 'codigo-civil-comercial', number: '118', order: 118, title: "Responsabilidad", originalText: "Responsabilidad. El tutor es responsable del daño causado al tutelado por su culpa, por acción u omisión, en el ejercicio o en ocasión de sus funciones. El tutelado, cualquiera de sus parientes, o el Ministerio Público pueden solicitar judicialmente las providencias necesarias para remediarlo, sin perjuicio de que sean adoptadas de oficio.", currentText: "Responsabilidad. El tutor es responsable del daño causado al tutelado por su culpa, por acción u omisión, en el ejercicio o en ocasión de sus funciones. El tutelado, cualquiera de sus parientes, o el Ministerio Público pueden solicitar judicialmente las providencias necesarias para remediarlo, sin perjuicio de que sean adoptadas de oficio.", plainLanguageExplanation: "Establece el régimen de responsabilidad. El tutor es responsable del daño causado al tutelado por su culpa, por acción u omisión, en el ejercicio o en ocasión de sus funciones.", practicalEffects: ['En la práctica, este artículo rige responsabilidad. El tutor es responsable del daño causado al tutelado por su culpa, por acción u omisión, en el ejercicio o en ocasión de sus funciones.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidadarticulo 118'], segments: [], amendments: [] },
  { id: 'ccyc-art-119', lawId: 'codigo-civil-comercial', number: '119', order: 119, title: "Educación y alimentos", originalText: "Educación y alimentos. El juez debe fijar las sumas requeridas para la educación y alimentos del niño, niña o adolescente, ponderando la cuantía de sus bienes y la renta que producen, sin perjuicio de su adecuación conforme a las circunstancias. Si los recursos de la persona sujeta a tutela no son suficientes para atender a su cuidado y educación, el tutor puede, con autorización judicial, demandar alimentos a los obligados a prestarlos.", currentText: "Educación y alimentos. El juez debe fijar las sumas requeridas para la educación y alimentos del niño, niña o adolescente, ponderando la cuantía de sus bienes y la renta que producen, sin perjuicio de su adecuación conforme a las circunstancias. Si los recursos de la persona sujeta a tutela no son suficientes para atender a su cuidado y educación, el tutor puede, con autorización judicial, demandar alimentos a los obligados a prestarlos.", plainLanguageExplanation: "Establece el régimen de educación y alimentos. El juez debe fijar las sumas requeridas para la educación y alimentos del niño, niña o adolescente, ponderando la cuantía de sus bienes y la renta que producen, sin perjuicio de su adecuación conforme a las circunstancias.", practicalEffects: ['En la práctica, este artículo rige educación y alimentos. El juez debe fijar las sumas requeridas para la educación y alimentos del niño, niña o adolescente, ponderando la cuantía de sus bienes y la renta que'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['educacin', 'alimentos', 'articulo 119'], segments: [], amendments: [] },
  { id: 'ccyc-art-120', lawId: 'codigo-civil-comercial', number: '120', order: 120, title: "Actos prohibidos", originalText: "Actos prohibidos. Quien ejerce la tutela no puede, ni con autorización judicial, celebrar con su tutelado los actos prohibidos a los padres respecto de sus hijos menores de edad. Antes de aprobada judicialmente la cuenta final, el tutor no puede celebrar contrato alguno con el pupilo, aunque haya cesado la incapacidad.", currentText: "Actos prohibidos. Quien ejerce la tutela no puede, ni con autorización judicial, celebrar con su tutelado los actos prohibidos a los padres respecto de sus hijos menores de edad. Antes de aprobada judicialmente la cuenta final, el tutor no puede celebrar contrato alguno con el pupilo, aunque haya cesado la incapacidad.", plainLanguageExplanation: "Establece el régimen de actos prohibidos. Quien ejerce la tutela no puede, ni con autorización judicial, celebrar con su tutelado los actos prohibidos a los padres respecto de sus hijos menores de edad.", practicalEffects: ['En la práctica, este artículo rige actos prohibidos. Quien ejerce la tutela no puede, ni con autorización judicial, celebrar con su tutelado los actos prohibidos a los padres respecto de sus hijos menores de edad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'prohibidos', 'articulo 120'], segments: [], amendments: [] },
  { id: 'ccyc-art-121', lawId: 'codigo-civil-comercial', number: '121', order: 121, title: "Actos que requieren autorización judicial", originalText: "Actos que requieren autorización judicial. Además de los actos para los cuales los padres necesitan autorización judicial, el tutor debe requerirla para los siguientes: a) adquirir inmuebles o cualquier bien que no sea útil para satisfacer los requerimientos alimentarios del tutelado; b) prestar dinero de su tutelado. La autorización sólo debe ser concedida si existen garantías reales suficientes; c) dar en locación los bienes del tutelado o celebrar contratos con finalidad análoga por plazo superior a tres años. En todos los casos, estos contratos concluyen cuando el tutelado alcanza la mayoría de edad; d) tomar en locación inmuebles que no sean la casa habitación; e) contraer deudas, repudiar herencias o donaciones, hacer transacciones y remitir créditos aunque el deudor sea insolvente; f) hacer gastos extraordinarios que no sean de reparación o conservación de los bienes; g) realizar todos aquellos actos en los que los parientes del tutor dentro del cuarto grado o segundo de afinidad, o sus socios o amigos íntimos están directa o indirectamente interesados.", currentText: "Actos que requieren autorización judicial. Además de los actos para los cuales los padres necesitan autorización judicial, el tutor debe requerirla para los siguientes: a) adquirir inmuebles o cualquier bien que no sea útil para satisfacer los requerimientos alimentarios del tutelado; b) prestar dinero de su tutelado. La autorización sólo debe ser concedida si existen garantías reales suficientes; c) dar en locación los bienes del tutelado o celebrar contratos con finalidad análoga por plazo superior a tres años. En todos los casos, estos contratos concluyen cuando el tutelado alcanza la mayoría de edad; d) tomar en locación inmuebles que no sean la casa habitación; e) contraer deudas, repudiar herencias o donaciones, hacer transacciones y remitir créditos aunque el deudor sea insolvente; f) hacer gastos extraordinarios que no sean de reparación o conservación de los bienes; g) realizar todos aquellos actos en los que los parientes del tutor dentro del cuarto grado o segundo de afinidad, o sus socios o amigos íntimos están directa o indirectamente interesados.", plainLanguageExplanation: "Establece el régimen de actos que requieren autorización judicial. Además de los actos para los cuales los padres necesitan autorización judicial, el tutor debe requerirla para los siguientes: a) adquirir inmuebles o cualquier bien que no sea útil para satisfacer los requerimientos alimentarios del tutelado; b) prestar dinero de su tutelado.", practicalEffects: ['En la práctica, este artículo rige actos que requieren autorización judicial. Además de los actos para los cuales los padres necesitan autorización judicial, el tutor debe requerirla para los siguientes: a) adquirir inmuebles o'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'requieren', 'autorizacin', 'judicial', 'articulo 121'], segments: [], amendments: [] },
  { id: 'ccyc-art-122', lawId: 'codigo-civil-comercial', number: '122', order: 122, title: "Derechos reales sobre bienes del tutelado", originalText: "Derechos reales sobre bienes del tutelado. El juez puede autorizar la transmisión, constitución o modificación de derechos reales sobre los bienes del niño, niña o adolescente sólo si media conveniencia evidente. Los bienes que tienen valor afectivo o cultural sólo pueden ser vendidos en caso de absoluta necesidad.", currentText: "Derechos reales sobre bienes del tutelado. El juez puede autorizar la transmisión, constitución o modificación de derechos reales sobre los bienes del niño, niña o adolescente sólo si media conveniencia evidente. Los bienes que tienen valor afectivo o cultural sólo pueden ser vendidos en caso de absoluta necesidad.", plainLanguageExplanation: "Establece el régimen de derechos reales sobre bienes del tutelado. El juez puede autorizar la transmisión, constitución o modificación de derechos reales sobre los bienes del niño, niña o adolescente sólo si media conveniencia evidente.", practicalEffects: ['En la práctica, este artículo rige derechos reales sobre bienes del tutelado. El juez puede autorizar la transmisión, constitución o modificación de derechos reales sobre los bienes del niño, niña o adolescente sólo si media conveniencia evidente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos', 'reales', 'sobre', 'bienes', 'tutelado', 'articulo 122'], segments: [], amendments: [] },
  { id: 'ccyc-art-123', lawId: 'codigo-civil-comercial', number: '123', order: 123, title: "Forma de la venta", originalText: "Forma de la venta. La venta debe hacerse en subasta pública, excepto que se trate de muebles de escaso valor, o si a juicio del juez, la venta extrajudicial puede ser más conveniente y el precio que se ofrece es superior al de la tasación.", currentText: "Forma de la venta. La venta debe hacerse en subasta pública, excepto que se trate de muebles de escaso valor, o si a juicio del juez, la venta extrajudicial puede ser más conveniente y el precio que se ofrece es superior al de la tasación.", plainLanguageExplanation: "Establece el régimen de forma de la venta. La venta debe hacerse en subasta pública, excepto que se trate de muebles de escaso valor, o si a juicio del juez, la venta extrajudicial puede ser más conveniente y el precio que se ofrece es superior al de la tasación.", practicalEffects: ['En la práctica, este artículo rige forma de la venta. La venta debe hacerse en subasta pública, excepto que se trate de muebles de escaso valor, o si a juicio del juez, la venta extrajudicial puede ser má'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['forma', 'venta', 'articulo 123'], segments: [], amendments: [] },
  { id: 'ccyc-art-124', lawId: 'codigo-civil-comercial', number: '124', order: 124, title: "Dinero", originalText: "Dinero. Luego de ser cubiertos los gastos de la tutela, el dinero del tutelado debe ser colocado a interés en bancos de reconocida solvencia, o invertido en títulos públicos, a su nombre y a la orden del juez con referencia a los autos a que pertenece. El tutor no puede retirar fondos, títulos o valores sin autorización judicial.", currentText: "Dinero. Luego de ser cubiertos los gastos de la tutela, el dinero del tutelado debe ser colocado a interés en bancos de reconocida solvencia, o invertido en títulos públicos, a su nombre y a la orden del juez con referencia a los autos a que pertenece. El tutor no puede retirar fondos, títulos o valores sin autorización judicial.", plainLanguageExplanation: "Establece el régimen de dinero. Luego de ser cubiertos los gastos de la tutela, el dinero del tutelado debe ser colocado a interés en bancos de reconocida solvencia, o invertido en títulos públicos, a su nombre y a la orden del juez con referencia a los autos a que pertenece.", practicalEffects: ['En la práctica, este artículo rige dinero. Luego de ser cubiertos los gastos de la tutela, el dinero del tutelado debe ser colocado a interés en bancos de reconocida solvencia, o invertido en t'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['dineroarticulo 124'], segments: [], amendments: [] },
  { id: 'ccyc-art-125', lawId: 'codigo-civil-comercial', number: '125', order: 125, title: "Fideicomiso y otras inversiones seguras", originalText: "Fideicomiso y otras inversiones seguras. El juez también puede autorizar que los bienes sean transmitidos en fideicomiso a una entidad autorizada para ofrecerse públicamente como fiduciario, siempre que el tutelado sea el beneficiario. Asimismo, puede disponer otro tipo de inversiones seguras, previo dictamen técnico.", currentText: "Fideicomiso y otras inversiones seguras. El juez también puede autorizar que los bienes sean transmitidos en fideicomiso a una entidad autorizada para ofrecerse públicamente como fiduciario, siempre que el tutelado sea el beneficiario. Asimismo, puede disponer otro tipo de inversiones seguras, previo dictamen técnico.", plainLanguageExplanation: "Establece el régimen de fideicomiso y otras inversiones seguras. El juez también puede autorizar que los bienes sean transmitidos en fideicomiso a una entidad autorizada para ofrecerse públicamente como fiduciario, siempre que el tutelado sea el beneficiario.", practicalEffects: ['En la práctica, este artículo rige fideicomiso y otras inversiones seguras. El juez también puede autorizar que los bienes sean transmitidos en fideicomiso a una entidad autorizada para ofrecerse públicamente como fiduciario, siempre que el tutelado sea el beneficiario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fideicomiso', 'otras', 'inversiones', 'seguras', 'articulo 125'], segments: [], amendments: [] },
  { id: 'ccyc-art-126', lawId: 'codigo-civil-comercial', number: '126', order: 126, title: "Sociedad", originalText: "Sociedad. Si el tutelado tiene parte en una sociedad, el tutor está facultado para ejercer los derechos que corresponden al socio a quien el tutelado ha sucedido. Si tiene que optar entre la continuación y la disolución de la sociedad, el juez debe decidir previo informe del tutor.", currentText: "Sociedad. Si el tutelado tiene parte en una sociedad, el tutor está facultado para ejercer los derechos que corresponden al socio a quien el tutelado ha sucedido. Si tiene que optar entre la continuación y la disolución de la sociedad, el juez debe decidir previo informe del tutor.", plainLanguageExplanation: "Establece el régimen de sociedad. Si el tutelado tiene parte en una sociedad, el tutor está facultado para ejercer los derechos que corresponden al socio a quien el tutelado ha sucedido.", practicalEffects: ['En la práctica, este artículo rige sociedad. Si el tutelado tiene parte en una sociedad, el tutor está facultado para ejercer los derechos que corresponden al socio a quien el tutelado ha sucedido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sociedadarticulo 126'], segments: [], amendments: [] },
  { id: 'ccyc-art-127', lawId: 'codigo-civil-comercial', number: '127', order: 127, title: "Fondo de comercio", originalText: "Fondo de comercio. Si el tutelado es propietario de un fondo de comercio, el tutor está autorizado para ejecutar todos los actos de administración ordinaria propios del establecimiento. Los actos que exceden de aquélla, deben ser autorizados judicialmente. Si la continuación de la explotación resulta perjudicial, el juez debe autorizar el cese del negocio facultando al tutor para enajenarlo, previa tasación, en subasta pública o venta privada, según sea más conveniente. Mientras no se venda, el tutor está autorizado para proceder como mejor convenga a los intereses del tutelado.", currentText: "Fondo de comercio. Si el tutelado es propietario de un fondo de comercio, el tutor está autorizado para ejecutar todos los actos de administración ordinaria propios del establecimiento. Los actos que exceden de aquélla, deben ser autorizados judicialmente. Si la continuación de la explotación resulta perjudicial, el juez debe autorizar el cese del negocio facultando al tutor para enajenarlo, previa tasación, en subasta pública o venta privada, según sea más conveniente. Mientras no se venda, el tutor está autorizado para proceder como mejor convenga a los intereses del tutelado.", plainLanguageExplanation: "Establece el régimen de fondo de comercio. Si el tutelado es propietario de un fondo de comercio, el tutor está autorizado para ejecutar todos los actos de administración ordinaria propios del establecimiento.", practicalEffects: ['En la práctica, este artículo rige fondo de comercio. Si el tutelado es propietario de un fondo de comercio, el tutor está autorizado para ejecutar todos los actos de administración ordinaria propios del establecimiento.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['fondo', 'comercio', 'articulo 127'], segments: [], amendments: [] },
  { id: 'ccyc-art-128', lawId: 'codigo-civil-comercial', number: '128', order: 128, title: "Retribución del tutor", originalText: "Retribución del tutor. El tutor tiene derecho a la retribución que se fije judicialmente teniendo en cuenta la importancia de los bienes del tutelado y el trabajo que ha demandado su administración en cada período. En caso de tratarse de tutela ejercida por dos personas, la remuneración debe ser única y distribuida entre ellos según criterio judicial. La remuneración única no puede exceder de la décima parte de los frutos líquidos de los bienes del menor de edad. El guardador que ejerce funciones de tutela también tiene derecho a la retribución. Los frutos pendientes al comienzo de la tutela y a su finalización deben computarse a los efectos de la retribución, en la medida en que la gestión haya sido útil para su percepción.", currentText: "Retribución del tutor. El tutor tiene derecho a la retribución que se fije judicialmente teniendo en cuenta la importancia de los bienes del tutelado y el trabajo que ha demandado su administración en cada período. En caso de tratarse de tutela ejercida por dos personas, la remuneración debe ser única y distribuida entre ellos según criterio judicial. La remuneración única no puede exceder de la décima parte de los frutos líquidos de los bienes del menor de edad. El guardador que ejerce funciones de tutela también tiene derecho a la retribución. Los frutos pendientes al comienzo de la tutela y a su finalización deben computarse a los efectos de la retribución, en la medida en que la gestión haya sido útil para su percepción.", plainLanguageExplanation: "Establece el régimen de retribución del tutor. El tutor tiene derecho a la retribución que se fije judicialmente teniendo en cuenta la importancia de los bienes del tutelado y el trabajo que ha demandado su administración en cada período.", practicalEffects: ['En la práctica, este artículo rige retribución del tutor. El tutor tiene derecho a la retribución que se fije judicialmente teniendo en cuenta la importancia de los bienes del tutelado y el trabajo que ha demandado su administración en cada período.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['retribucin', 'tutor', 'articulo 128'], segments: [], amendments: [] },
  { id: 'ccyc-art-129', lawId: 'codigo-civil-comercial', number: '129', order: 129, title: "Cese del derecho a la retribución", originalText: "Cese del derecho a la retribución. El tutor no tiene derecho a retribución: a) si nombrado por un testador, éste ha dejado algún legado que puede estimarse remuneratorio de su gestión. Puede optar por renunciar al legado o devolverlo, percibiendo la retribución legal; b) si las rentas del pupilo no alcanzan para satisfacer los gastos de sus alimentos y educación; c) si fue removido de la tutela por causa atribuible a su culpa o dolo, caso en el cual debe también restituir lo percibido, sin perjuicio de las responsabilidades por los daños que cause; d) si contrae matrimonio con el tutelado sin la debida dispensa judicial. Parágrafo 4° Cuentas de la tutela", currentText: "Cese del derecho a la retribución. El tutor no tiene derecho a retribución: a) si nombrado por un testador, éste ha dejado algún legado que puede estimarse remuneratorio de su gestión. Puede optar por renunciar al legado o devolverlo, percibiendo la retribución legal; b) si las rentas del pupilo no alcanzan para satisfacer los gastos de sus alimentos y educación; c) si fue removido de la tutela por causa atribuible a su culpa o dolo, caso en el cual debe también restituir lo percibido, sin perjuicio de las responsabilidades por los daños que cause; d) si contrae matrimonio con el tutelado sin la debida dispensa judicial. Parágrafo 4° Cuentas de la tutela", plainLanguageExplanation: "Establece el régimen de cese del derecho a la retribución. El tutor no tiene derecho a retribución: a) si nombrado por un testador, éste ha dejado algún legado que puede estimarse remuneratorio de su gestión.", practicalEffects: ['En la práctica, este artículo rige cese del derecho a la retribución. El tutor no tiene derecho a retribución: a) si nombrado por un testador, éste ha dejado algún legado que puede estimarse remuneratorio de su gestión.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cese', 'derecho', 'retribucin', 'articulo 129'], segments: [], amendments: [] },
  { id: 'ccyc-art-130', lawId: 'codigo-civil-comercial', number: '130', order: 130, title: "Deber de rendir cuentas", originalText: "Deber de rendir cuentas. Periodicidad. Quien ejerce la tutela debe llevar cuenta fiel y documentada de las entradas y gastos de su gestión. Debe rendir cuentas: al término de cada año, al cesar en el cargo, y cuando el juez lo ordena, de oficio, o a petición del Ministerio Público. La obligación de rendición de cuentas es individual y su aprobación sólo libera a quien da cumplimiento a la misma. Aprobada la cuenta del primer año, puede disponerse que las posteriores se rindan en otros plazos, cuando la naturaleza de la administración así lo justifique.", currentText: "Deber de rendir cuentas. Periodicidad. Quien ejerce la tutela debe llevar cuenta fiel y documentada de las entradas y gastos de su gestión. Debe rendir cuentas: al término de cada año, al cesar en el cargo, y cuando el juez lo ordena, de oficio, o a petición del Ministerio Público. La obligación de rendición de cuentas es individual y su aprobación sólo libera a quien da cumplimiento a la misma. Aprobada la cuenta del primer año, puede disponerse que las posteriores se rindan en otros plazos, cuando la naturaleza de la administración así lo justifique.", plainLanguageExplanation: "Establece el régimen de deber de rendir cuentas. Periodicidad.", practicalEffects: ['En la práctica, este artículo rige deber de rendir cuentas. Periodicidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deber', 'rendir', 'cuentas', 'articulo 130'], segments: [], amendments: [] },
];
